function AlertBannerPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab, setTab]         = useState<"overview" | "playground" | "reference">("overview")
  const [pgState, setPgState] = useState<AlertBannerState>("error")
  const [pgCta, setPgCta]     = useState(false)
  const [pgDesc, setPgDesc]   = useState(true)
  const [dismissed, setDismissed] = useState(false)

  const STATES: AlertBannerState[] = ["error", "success", "alert"]

  const OVERVIEW_ROWS: { state: AlertBannerState; title: string; description: string }[] = [
    { state: "error",   title: "Unable to save changes",       description: "Your session may have expired. Please try again or refresh the page." },
    { state: "success", title: "Changes saved successfully",   description: "All your updates have been applied and are now live." },
    { state: "alert",   title: "Action required before July 8", description: "Your subscription expires soon. Renew now to avoid service interruption." },
  ]

  const pgTitle = {
    error:   "Unable to save changes",
    success: "Changes saved successfully",
    alert:   "Action required before July 8",
  }[pgState]

  const pgDescription = {
    error:   "Your session may have expired. Please try again or refresh the page.",
    success: "All your updates have been applied and are now live.",
    alert:   "Your subscription expires soon. Renew now to avoid service interruption.",
  }[pgState]

  return (
    <div>
      {/* Header */}
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Alert Banner</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px] max-w-[560px]">
            Full-width contextual notice for system-level feedback. Three semantic states — Error, Success, Alert — with an optional CTA action and dismiss button.
          </p>
        </div>
        <SpecButton onClick={() => openSpec("alert-banner")} />
      </div>

      {/* Tabs */}
      <div className="flex gap-[4px] mb-[32px] border-b border-[var(--table-border)]">
        {(["overview", "playground", "reference"] as const).map(t => (
          <button
            key={t}
            onClick={() => setTab(t)}
            className="px-[14px] py-[8px] text-[13px] font-semibold capitalize transition-colors"
            style={{
              color: tab === t ? "var(--primary)" : "var(--field-supporting)",
              borderBottom: tab === t ? "2px solid var(--primary)" : "2px solid transparent",
              marginBottom: -1,
            }}
          >
            {t.charAt(0).toUpperCase() + t.slice(1)}
          </button>
        ))}
      </div>

      {/* ── Overview ─────────────────────────────────────────────────────────── */}
      {tab === "overview" && (
        <div className="flex flex-col gap-[40px]">
          {/* All states */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">All states</p>
            <div className="flex flex-col gap-[8px]">
              {OVERVIEW_ROWS.map(r => (
                <AlertBanner key={r.state} state={r.state} title={r.title} description={r.description} />
              ))}
            </div>
          </section>

          {/* With CTA */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">With CTA + dismiss</p>
            <div className="flex flex-col gap-[8px]">
              <AlertBanner state="error"   title="Unable to save changes"        description="Your session may have expired." cta="Retry"  onClose={() => {}} />
              <AlertBanner state="success" title="Changes saved successfully"    description="All updates are now live."       cta="Review" onClose={() => {}} />
              <AlertBanner state="alert"   title="Action required before July 8" description="Renew now to avoid interruption." cta="Renew" onClose={() => {}} />
            </div>
          </section>

          {/* Title only */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Title only + dismiss</p>
            <div className="flex flex-col gap-[8px]">
              <AlertBanner state="error"   title="Connection failed"       onClose={() => {}} />
              <AlertBanner state="success" title="Export complete"         onClose={() => {}} />
              <AlertBanner state="alert"   title="Maintenance window soon" onClose={() => {}} />
            </div>
          </section>

          {/* Usage */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Usage guidelines</p>
            <div className="grid grid-cols-2 gap-[16px]">
              <div className="rounded-[8px] border border-[var(--table-border)] p-[16px] flex flex-col gap-[8px]">
                <p className="text-[11px] font-semibold text-[#059669] uppercase tracking-widest">Use when</p>
                <ul className="flex flex-col gap-[6px]">
                  {["System-level action needed from the user", "Non-blocking status feedback (success, warning)", "Page-level validation errors after form submission", "Temporary notice that can be dismissed"].map(t => (
                    <li key={t} className="text-[13px] text-[var(--field-supporting)] leading-[1.5] flex gap-[8px]">
                      <span className="text-[#059669] shrink-0">✓</span>{t}
                    </li>
                  ))}
                </ul>
              </div>
              <div className="rounded-[8px] border border-[var(--table-border)] p-[16px] flex flex-col gap-[8px]">
                <p className="text-[11px] font-semibold text-[#dc2626] uppercase tracking-widest">Don't use when</p>
                <ul className="flex flex-col gap-[6px]">
                  {["Inline field validation (use Input error state)", "Inline hints or helper text (use Input supporting)", "Critical alerts requiring user confirmation (use Modal)", "Marketing messages or promotions"].map(t => (
                    <li key={t} className="text-[13px] text-[var(--field-supporting)] leading-[1.5] flex gap-[8px]">
                      <span className="text-[#dc2626] shrink-0">✕</span>{t}
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          </section>
        </div>
      )}

      {/* ── Playground ───────────────────────────────────────────────────────── */}
      {tab === "playground" && (
        <div className="flex flex-col gap-[32px]">
          {/* Live preview */}
          <div className="rounded-[12px] border border-[var(--table-border)] bg-[var(--code-bg)] p-[32px] flex items-center justify-center min-h-[120px]">
            {dismissed ? (
              <div className="flex flex-col items-center gap-[12px]">
                <p className="text-[13px] text-[var(--field-supporting)]">Banner dismissed</p>
                <button
                  onClick={() => setDismissed(false)}
                  className="text-[12px] font-semibold text-[var(--primary)] hover:opacity-70 transition-opacity"
                >
                  Show again
                </button>
              </div>
            ) : (
              <div className="w-full max-w-[600px]">
                <AlertBanner
                  state={pgState}
                  title={pgTitle}
                  description={pgDesc ? pgDescription : undefined}
                  cta={pgCta ? (pgState === "success" ? "Review" : pgState === "error" ? "Retry" : "Renew") : undefined}
                  onCta={() => {}}
                  onClose={() => setDismissed(true)}
                />
              </div>
            )}
          </div>

          {/* Controls */}
          <div className="flex flex-col gap-[16px]">
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)]">Controls</p>
            <div className="grid grid-cols-3 gap-[12px]">
              {/* State */}
              <div className="flex flex-col gap-[8px]">
                <span className="text-[12px] font-semibold text-[var(--field-label)]">State</span>
                <div className="flex flex-col gap-[4px]">
                  {STATES.map(s => (
                    <button
                      key={s}
                      onClick={() => { setPgState(s); setDismissed(false) }}
                      className="flex items-center gap-[8px] px-[12px] py-[7px] rounded-[8px] text-[13px] font-medium text-left transition-colors"
                      style={{
                        background: pgState === s ? "var(--ctrl-inactive-bg)" : "transparent",
                        color: pgState === s ? "var(--foreground)" : "var(--field-supporting)",
                        border: pgState === s ? "1px solid var(--table-border)" : "1px solid transparent",
                      }}
                    >
                      <span className="w-[8px] h-[8px] rounded-full shrink-0" style={{
                        background: s === "error" ? "var(--ab-error-icon)" : s === "success" ? "var(--ab-success-icon)" : "var(--ab-alert-icon)"
                      }} />
                      {s.charAt(0).toUpperCase() + s.slice(1)}
                    </button>
                  ))}
                </div>
              </div>

              {/* Description toggle */}
              <div className="flex flex-col gap-[8px]">
                <span className="text-[12px] font-semibold text-[var(--field-label)]">Description</span>
                <div className="flex flex-col gap-[4px]">
                  {[true, false].map(v => (
                    <button
                      key={String(v)}
                      onClick={() => setPgDesc(v)}
                      className="flex items-center gap-[8px] px-[12px] py-[7px] rounded-[8px] text-[13px] font-medium text-left transition-colors"
                      style={{
                        background: pgDesc === v ? "var(--ctrl-inactive-bg)" : "transparent",
                        color: pgDesc === v ? "var(--foreground)" : "var(--field-supporting)",
                        border: pgDesc === v ? "1px solid var(--table-border)" : "1px solid transparent",
                      }}
                    >
                      {v ? "With description" : "Title only"}
                    </button>
                  ))}
                </div>
              </div>

              {/* CTA toggle */}
              <div className="flex flex-col gap-[8px]">
                <span className="text-[12px] font-semibold text-[var(--field-label)]">CTA button</span>
                <div className="flex flex-col gap-[4px]">
                  {[false, true].map(v => (
                    <button
                      key={String(v)}
                      onClick={() => setPgCta(v)}
                      className="flex items-center gap-[8px] px-[12px] py-[7px] rounded-[8px] text-[13px] font-medium text-left transition-colors"
                      style={{
                        background: pgCta === v ? "var(--ctrl-inactive-bg)" : "transparent",
                        color: pgCta === v ? "var(--foreground)" : "var(--field-supporting)",
                        border: pgCta === v ? "1px solid var(--table-border)" : "1px solid transparent",
                      }}
                    >
                      {v ? "CTA: true" : "CTA: false"}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          {/* Code snippet */}
          <div className="flex flex-col gap-[8px]">
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)]">Usage</p>
            <pre className="rounded-[8px] bg-[var(--code-bg)] border border-[var(--table-border)] p-[16px] text-[12px] font-mono text-[var(--field-text)] overflow-x-auto leading-[1.7]">{`import { AlertBanner } from "@/components/ui/alert-banner"

<AlertBanner
  state="${pgState}"
  title="${pgTitle}"${pgDesc ? `\n  description="..."` : ""}${pgCta ? `\n  cta="${pgState === "success" ? "Review" : pgState === "error" ? "Retry" : "Renew"}"` : ""}
  onClose={() => setVisible(false)}
/>`}</pre>
          </div>
        </div>
      )}

      {/* ── Reference ────────────────────────────────────────────────────────── */}
      {tab === "reference" && (
        <div className="flex flex-col gap-[32px]">
          {/* Props */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[12px]">Component props</p>
            <div className="rounded-[8px] border border-[var(--table-border)] overflow-hidden">
              <div className="grid grid-cols-[160px_120px_1fr] bg-[var(--table-header-bg)] border-b border-[var(--table-border)]">
                {["Prop", "Type", "Description"].map(h => (
                  <div key={h} className="px-[12px] py-[10px] text-[11px] font-semibold uppercase tracking-widest text-[var(--table-header-text)]">{h}</div>
                ))}
              </div>
              {[
                ["state",       '"error" | "success" | "alert"', 'Semantic variant. Default: "error"'],
                ["title",       "string",                        "Required. Main message (SemiBold 14px)"],
                ["description", "string?",                       "Optional supporting text below the title (80% opacity)"],
                ["cta",         "string?",                       "Label for the optional tertiary CTA button"],
                ["onCta",       "() => void",                    "Click handler for the CTA button"],
                ["onClose",     "() => void",                    "Renders a dismiss (×) button when provided"],
                ["className",   "string?",                       "Extra classes merged via cn()"],
              ].map(([prop, type, desc], i) => (
                <div key={prop} className="grid grid-cols-[160px_120px_1fr] border-b border-[var(--table-border)] last:border-0" style={{ background: i % 2 === 1 ? "var(--row-alt-bg)" : undefined }}>
                  <div className="px-[12px] py-[12px] text-[13px] font-mono text-[var(--primary)]">{prop}</div>
                  <div className="px-[12px] py-[12px] text-[12px] font-mono text-[var(--field-supporting)]">{type}</div>
                  <div className="px-[12px] py-[12px] text-[13px] text-[var(--field-text)]">{desc}</div>
                </div>
              ))}
            </div>
          </section>

          {/* Tokens */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[12px]">Design tokens — <code className="text-[var(--primary)]">--ab-{"{state}"}-{"{role}"}</code></p>
            <div className="rounded-[8px] border border-[var(--table-border)] overflow-hidden">
              <div className="grid grid-cols-[100px_200px_130px_130px] bg-[var(--table-header-bg)] border-b border-[var(--table-border)]">
                {["State", "Token", "Dark", "Light"].map(h => (
                  <div key={h} className="px-[12px] py-[10px] text-[11px] font-semibold uppercase tracking-widest text-[var(--table-header-text)]">{h}</div>
                ))}
              </div>
              {[
                ["error",   "--ab-error-bg",    "#2d1515",                "#fdeded"],
                ["",        "--ab-error-bd",    "transparent",            "rgba(153,34,34,0.25)"],
                ["",        "--ab-error-icon",  "#ff6467",                "#992222"],
                ["",        "--ab-error-text",  "#ff6467",                "#5f2120"],
                ["success", "--ab-success-bg",  "#0a1f1a",                "#e5fdf8"],
                ["",        "--ab-success-bd",  "transparent",            "rgba(0,153,120,0.25)"],
                ["",        "--ab-success-icon","#6ee7b7",                "#009978"],
                ["",        "--ab-success-text","#6ee7b7",                "#003328"],
                ["alert",   "--ab-alert-bg",    "#2d1a08",                "#ffeedb"],
                ["",        "--ab-alert-bd",    "transparent",            "rgba(180,83,9,0.25)"],
                ["",        "--ab-alert-icon",  "#fcd34d",                "#b45309"],
                ["",        "--ab-alert-text",  "#fcd34d",                "#663c00"],
                ["—",       "--ab-cta-text",    "rgba(255,255,255,0.60)", "rgba(0,0,0,0.55)"],
              ].map(([state, token, dark, light], i) => (
                <div key={token} className="grid grid-cols-[100px_200px_130px_130px] border-b border-[var(--table-border)] last:border-0" style={{ background: i % 2 === 1 ? "var(--row-alt-bg)" : undefined }}>
                  <div className="px-[12px] py-[10px] text-[12px] font-semibold text-[var(--field-text)]">{state}</div>
                  <div className="px-[12px] py-[10px] text-[12px] font-mono text-[var(--primary)]">{token}</div>
                  <div className="px-[12px] py-[10px] text-[12px] font-mono text-[var(--field-supporting)]">{dark}</div>
                  <div className="px-[12px] py-[10px] text-[12px] font-mono text-[var(--field-supporting)]">{light}</div>
                </div>
              ))}
            </div>
          </section>

          {/* Anatomy */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[12px]">Anatomy</p>
            <div className="rounded-[8px] border border-[var(--table-border)] overflow-hidden">
              <div className="grid grid-cols-[160px_1fr] bg-[var(--table-header-bg)] border-b border-[var(--table-border)]">
                {["Element", "Description"].map(h => (
                  <div key={h} className="px-[12px] py-[10px] text-[11px] font-semibold uppercase tracking-widest text-[var(--table-header-text)]">{h}</div>
                ))}
              </div>
              {[
                ["Container",    "Flex row · 12px padding · 8px gap · 8px radius · state bg + 1px border"],
                ["Icon",         "16×16px Lucide icon · mt-2px baseline alignment · state icon color"],
                ["Title",        "14px SemiBold · state text color · flex-1 to push actions right"],
                ["Description",  "14px Medium · same text token at 80% opacity · optional"],
                ["CTA button",   "13px SemiBold · no bg · state text color · 4px gap from close btn · optional"],
                ["Close button", "20×20px · X icon 14px · state text color · always paired with onClose prop"],
              ].map(([el, desc], i) => (
                <div key={el} className="grid grid-cols-[160px_1fr] border-b border-[var(--table-border)] last:border-0" style={{ background: i % 2 === 1 ? "var(--row-alt-bg)" : undefined }}>
                  <div className="px-[12px] py-[12px] text-[13px] font-semibold text-[var(--field-text)]">{el}</div>
                  <div className="px-[12px] py-[12px] text-[13px] text-[var(--field-supporting)]">{desc}</div>
                </div>
              ))}
            </div>
          </section>
        </div>
      )}
    </div>
  )
}

const DEMO_NAMES = ["Sarah Chen", "Marco Rivera", "Aisha Johnson", "Chris Park", "Luna Kim", "Rafael Torres"]

function AvatarPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab, setTab] = useState<"overview" | "playground" | "reference" | "specs">("overview")
  const [pgSize, setPgSize] = useState<AvatarSizeKey>("md")
  const [pgAvatarStyle, setPgAvatarStyle] = useState<"text" | "empty">("text")
  const [pgColor, setPgColor] = useState<AvatarColorKey | "auto">("auto")
  const [pgSelected, setPgSelected] = useState(false)
  const [pgName, setPgName] = useState("Sarah Chen")

  return (
    <div className="flex flex-col gap-0">
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Avatar</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px]">
            Circular badge representing a user or workspace. 3 style variants: Text (initials, 7 color variants auto-assigned from name), Photo (user image), Empty (neutral — no photo available). 5 sizes. Optional selected state for interactive contexts.
          </p>
        </div>
        <div className="flex items-center gap-[8px] shrink-0">
          <SpecButton onClick={() => openSpec("avatar")} />
          <FigmaLink href="https://www.figma.com/design/v6rmYKA2zmyXWOahlxLOeI/Design-System---AIMS-OS?node-id=4753-19229" />
        </div>
      </div>

      <TabBar
        tabs={[
          { id: "overview",   label: "Overview"   },
          { id: "playground", label: "Playground" },
          { id: "reference",  label: "Reference"  },
          { id: "specs",      label: "Specs"      },
        ]}
        active={tab}
        onChange={id => setTab(id as typeof tab)}
      />

      <div className="flex flex-col gap-[40px] pt-[32px]">

        {/* ── Overview ───────────────────────────────────────────────── */}
        {tab === "overview" && (
          <div className="flex flex-col gap-[24px]">

            {/* Style variants */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Style variants</h2>
              <p className="text-[13px] text-[var(--field-supporting)]">
                Three variants cover all cases. Text is the default — always brand blue, never recolored. Empty signals that no photo is available. Photo displays the actual user image.
              </p>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px]">
                <div className="flex flex-wrap gap-[40px] items-start">
                  {/* Text */}
                  <div className="flex flex-col gap-[12px]">
                    <span className="text-[11px] font-semibold uppercase tracking-wider" style={{ color: "var(--field-supporting)" }}>Text</span>
                    <div className="flex gap-[12px] items-end">
                      {DEMO_NAMES.slice(0, 4).map((name, i) => (
                        <div key={i} className="flex flex-col items-center gap-[6px]">
                          <AvatarCircle name={name} sizeKey="lg" avatarStyle="text" />
                          <span className="text-[10px]" style={{ color: "var(--field-supporting)" }}>{name.split(" ").map(w => w[0]).join("")}</span>
                        </div>
                      ))}
                    </div>
                    <p className="text-[11px]" style={{ color: "var(--field-supporting)" }}>7 color variants · auto-assigned from name</p>
                  </div>
                  {/* Empty */}
                  <div className="flex flex-col gap-[12px]">
                    <span className="text-[11px] font-semibold uppercase tracking-wider" style={{ color: "var(--field-supporting)" }}>Empty</span>
                    <div className="flex gap-[12px] items-end">
                      {DEMO_NAMES.slice(0, 4).map((name, i) => (
                        <div key={i} className="flex flex-col items-center gap-[6px]">
                          <AvatarCircle name={name} sizeKey="lg" avatarStyle="empty" />
                          <span className="text-[10px]" style={{ color: "var(--field-supporting)" }}>—</span>
                        </div>
                      ))}
                    </div>
                    <p className="text-[11px]" style={{ color: "var(--field-supporting)" }}>var(--tag-neutral-bg) · no photo available</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Color variants */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Color variants</h2>
              <p className="text-[13px] text-[var(--field-supporting)]">
                Text style supports 7 colors — auto-assigned from the user's name hash so the same name always yields the same color. Pass <code className="text-[12px] bg-[var(--code-bg)] px-[5px] py-[1px] rounded-[4px]">colorKey</code> to override explicitly. All colors pass white-text contrast in both light and dark mode.
              </p>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px]">
                <div className="flex flex-wrap gap-[20px] items-end">
                  {AVATAR_COLOR_KEYS.map((color, i) => (
                    <div key={color} className="flex flex-col items-center gap-[8px]">
                      <AvatarCircle name={DEMO_NAMES[i % DEMO_NAMES.length]} sizeKey="lg" colorKey={color} />
                      <span className="text-[10px] font-mono" style={{ color: "var(--field-supporting)" }}>{color}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Size scale */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Size scale</h2>
              <p className="text-[13px] text-[var(--field-supporting)]">
                5 sizes. XS and S show a single initial; M, L, and XXL show two initials.
              </p>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px]">
                <div className="flex flex-wrap gap-[32px] items-end">
                  {AVATAR_SIZE_SPECS.map(s => (
                    <div key={s.key} className="flex flex-col items-center gap-[8px]">
                      <AvatarCircle name="Sarah Chen" sizeKey={s.key} />
                      <div className="flex flex-col items-center gap-[1px]">
                        <span className="text-[12px] font-semibold" style={{ color: "var(--foreground)" }}>{s.label} · {s.px}px</span>
                        <span className="text-[10px]" style={{ color: "var(--field-supporting)" }}>{s.desc}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Selected state */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Selected state</h2>
              <p className="text-[13px] text-[var(--field-supporting)]">
                The selected state is <strong style={{ color: "var(--foreground)", fontWeight: 600 }}>only available in interactive contexts</strong> where the user can actively choose an avatar — for example a user-picker, team assignment, or contact selector. In read-only contexts such as table cells, topbar, and entity headers, avatars are display-only and never enter the selected state.
              </p>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px] flex gap-[40px] items-start flex-wrap">
                <div className="flex flex-col gap-[12px]">
                  <span className="text-[11px] font-semibold uppercase tracking-wider" style={{ color: "var(--field-supporting)" }}>Display-only (no selected)</span>
                  <div className="flex gap-[12px]">
                    {DEMO_NAMES.slice(0, 3).map(name => <AvatarCircle key={name} name={name} sizeKey="lg" />)}
                  </div>
                  <p className="text-[11px]" style={{ color: "var(--field-supporting)" }}>Table cells · topbar · entity headers</p>
                </div>
                <div className="flex flex-col gap-[12px]">
                  <span className="text-[11px] font-semibold uppercase tracking-wider" style={{ color: "var(--field-supporting)" }}>Interactive (selected available)</span>
                  <div className="flex gap-[12px]">
                    <AvatarCircle name="Sarah Chen" sizeKey="lg" />
                    <AvatarCircle name="Marco Rivera" sizeKey="lg" selected />
                    <AvatarCircle name="Aisha Johnson" sizeKey="lg" />
                  </div>
                  <p className="text-[11px]" style={{ color: "var(--field-supporting)" }}>User picker · team selector · contact list</p>
                </div>
              </div>
            </div>

            {/* Stacked group */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Stacked group</h2>
              <p className="text-[13px] text-[var(--field-supporting)]">
                Used in table cells to show collaborators. Avatars overlap by 25% of their size. An overflow counter (+N) appears when the list is truncated.
              </p>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px] flex gap-[32px] flex-wrap items-center">
                {([3, 5, 8] as const).map(count => (
                  <div key={count} className="flex flex-col gap-[8px] items-start">
                    <span className="text-[11px] font-semibold uppercase tracking-wider" style={{ color: "var(--field-supporting)" }}>
                      {count > 5 ? `${count} members, max 4 shown` : `${count} members`}
                    </span>
                    <div className="flex items-center">
                      {DEMO_NAMES.slice(0, Math.min(count, 4)).map((name, i) => (
                        <div
                          key={i}
                          style={{
                            marginLeft: i > 0 ? -6 : 0,
                            zIndex: 10 - i,
                            borderRadius: "50%",
                            boxShadow: "0 0 0 1.5px var(--background)",
                            display: "inline-flex", flexShrink: 0,
                          }}
                        >
                          <AvatarCircle name={name} sizeKey="md" />
                        </div>
                      ))}
                      {count > 4 && (
                        <div
                          style={{
                            width: 24, height: 24, borderRadius: "50%",
                            marginLeft: -6,
                            background: "var(--tag-neutral-bg)", color: "var(--tag-neutral-fg)",
                            fontSize: 9, fontWeight: 700, lineHeight: 1,
                            display: "flex", alignItems: "center", justifyContent: "center",
                            boxShadow: "0 0 0 1.5px var(--background)", flexShrink: 0,
                          }}
                        >
                          +{count - 4}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Anatomy */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Anatomy</h2>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px] flex flex-wrap gap-[32px]">
                <div className="flex flex-col gap-[4px]">
                  <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Text style bg</p>
                  <p className="text-[12px] text-[var(--field-supporting)]">var(--av-col-{"{color}"}-bg) — 7 variants, auto from name hash</p>
                </div>
                <div className="flex flex-col gap-[4px]">
                  <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Empty style bg</p>
                  <p className="text-[12px] text-[var(--field-supporting)]">var(--tag-neutral-bg) = surface/neutral/default</p>
                </div>
                <div className="flex flex-col gap-[4px]">
                  <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Text color</p>
                  <p className="text-[12px] text-[var(--field-supporting)]">#ffffff, Inter SemiBold 600 — always white</p>
                </div>
                <div className="flex flex-col gap-[4px]">
                  <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Border</p>
                  <p className="text-[12px] text-[var(--field-supporting)]">var(--topbar-avatar-ring) = Border/Primary/Lighter</p>
                </div>
                <div className="flex flex-col gap-[4px]">
                  <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Initials</p>
                  <p className="text-[12px] text-[var(--field-supporting)]">XS/S → 1 character · M/L/XXL → 2 characters</p>
                </div>
                <div className="flex flex-col gap-[4px]">
                  <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Selected</p>
                  <p className="text-[12px] text-[var(--field-supporting)]">White border + drop-shadow 0 0 10px rgba(33,115,255,0.5) — interactive contexts only</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ── Playground ─────────────────────────────────────────────── */}
        {tab === "playground" && (
          <div className="flex flex-col gap-[20px]">
            <div className="rounded-md border border-[var(--field-border)] p-[20px] flex flex-col gap-[16px]">
              <CtrlGroup
                label="Size"
                options={AVATAR_SIZE_SPECS.map(s => ({ label: `${s.label} — ${s.px}px`, value: s.key }))}
                value={pgSize}
                onChange={v => setPgSize(v as AvatarSizeKey)}
              />
              <CtrlGroup
                label="Style"
                options={[
                  { label: "Text", value: "text" },
                  { label: "Empty", value: "empty" },
                ]}
                value={pgAvatarStyle}
                onChange={v => setPgAvatarStyle(v as "text" | "empty")}
              />
              {pgAvatarStyle === "text" && (
                <CtrlGroup
                  label="Color"
                  options={[
                    { label: "Auto", value: "auto" },
                    ...AVATAR_COLOR_KEYS.map(c => ({ label: c.charAt(0).toUpperCase() + c.slice(1), value: c })),
                  ]}
                  value={pgColor}
                  onChange={v => setPgColor(v as AvatarColorKey | "auto")}
                />
              )}
              <CtrlGroup
                label="State"
                options={[
                  { label: "Default", value: "false" },
                  { label: "Selected", value: "true" },
                ]}
                value={pgSelected ? "true" : "false"}
                onChange={v => setPgSelected(v === "true")}
              />
              {pgAvatarStyle === "text" && (
                <div className="flex flex-col gap-[6px]">
                  <p className="text-[12px] font-medium text-[var(--field-supporting)]">Name (for initials)</p>
                  <input
                    type="text"
                    value={pgName}
                    onChange={e => setPgName(e.target.value)}
                    placeholder="First Last"
                    className="h-[32px] px-[8px] text-[12px] rounded-[6px] border border-[var(--field-border)] bg-[var(--field-bg)] text-[var(--field-text)] placeholder:text-[var(--field-supporting)] outline-none focus:border-[#2173ff] transition-colors"
                  />
                </div>
              )}
            </div>
            <div className="flex items-center justify-center min-h-[120px] rounded-md border border-[var(--field-border)] border-dashed">
              <AvatarCircle
                name={pgName || "?"}
                sizeKey={pgSize}
                avatarStyle={pgAvatarStyle}
                colorKey={pgColor !== "auto" ? pgColor : undefined}
                selected={pgSelected}
              />
            </div>
          </div>
        )}

        {/* ── Reference ──────────────────────────────────────────────── */}
        {tab === "reference" && (
          <div className="flex flex-col gap-[24px]">
            <Row label="Text — all sizes, default state">
              {AVATAR_SIZE_SPECS.map(s => (
                <div key={s.key} className="flex flex-col items-center gap-[4px]">
                  <AvatarCircle name="Sarah Chen" sizeKey={s.key} avatarStyle="text" />
                  <span className="text-[10px]" style={{ color: "var(--field-supporting)" }}>{s.label} {s.px}px</span>
                </div>
              ))}
            </Row>
            <Row label="Text — all sizes, selected state (interactive contexts only)">
              {AVATAR_SIZE_SPECS.map(s => (
                <div key={s.key} className="flex flex-col items-center gap-[4px]">
                  <AvatarCircle name="Sarah Chen" sizeKey={s.key} avatarStyle="text" selected />
                  <span className="text-[10px]" style={{ color: "var(--field-supporting)" }}>{s.label} {s.px}px</span>
                </div>
              ))}
            </Row>
            <Row label="Empty — all sizes (no photo available)">
              {AVATAR_SIZE_SPECS.map(s => (
                <div key={s.key} className="flex flex-col items-center gap-[4px]">
                  <AvatarCircle name="?" sizeKey={s.key} avatarStyle="empty" />
                  <span className="text-[10px]" style={{ color: "var(--field-supporting)" }}>{s.label} {s.px}px</span>
                </div>
              ))}
            </Row>
            <Row label="Text — multiple users, Size M">
              {DEMO_NAMES.map(name => (
                <div key={name} className="flex flex-col items-center gap-[4px]">
                  <AvatarCircle name={name} sizeKey="md" avatarStyle="text" />
                  <span className="text-[10px]" style={{ color: "var(--field-supporting)" }}>{name.split(" ").map(w => w[0]).join("")}</span>
                </div>
              ))}
            </Row>
            <Row label="Stacked group — Size M (max 4 + overflow)">
              <div className="flex items-center">
                {DEMO_NAMES.slice(0, 4).map((name, i) => (
                  <div key={i} style={{ marginLeft: i > 0 ? -6 : 0, zIndex: 10 - i, borderRadius: "50%", boxShadow: "0 0 0 1.5px var(--background)", display: "inline-flex", flexShrink: 0 }}>
                    <AvatarCircle name={name} sizeKey="md" />
                  </div>
                ))}
                <div style={{ width: 24, height: 24, borderRadius: "50%", marginLeft: -6, background: "var(--tag-neutral-bg)", color: "var(--tag-neutral-fg)", fontSize: 9, fontWeight: 700, lineHeight: 1, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 0 0 1.5px var(--background)", flexShrink: 0 }}>
                  +{DEMO_NAMES.length - 4}
                </div>
              </div>
            </Row>
          </div>
        )}

        {/* ── Specs ──────────────────────────────────────────────────── */}
        {tab === "specs" && (
          <div className="flex flex-col gap-[32px]">

            {/* Size table */}
            <section className="flex flex-col gap-[12px]">
              <h2 className="text-[13px] font-semibold uppercase tracking-[0.06em] text-[var(--field-supporting)]">Sizes</h2>
              <div className="rounded-[8px] overflow-hidden" style={{ border: "1px solid var(--table-border)" }}>
                <table className="w-full text-[12px]">
                  <thead>
                    <tr style={{ background: "var(--table-header-bg)", borderBottom: "1px solid var(--table-border)" }}>
                      {["Size", "Diameter", "Font size", "Initials", "Typical use"].map(h => (
                        <th key={h} className="text-left px-[14px] py-[10px] font-semibold text-[var(--field-supporting)]">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {AVATAR_SIZE_SPECS.map((s, i, arr) => (
                      <tr key={s.key} style={{ borderBottom: i < arr.length - 1 ? "1px solid var(--table-border)" : "none" }}>
                        <td className="px-[14px] py-[9px] font-semibold text-[var(--foreground)]">{s.label}</td>
                        <td className="px-[14px] py-[9px] font-mono text-[var(--field-supporting)]">{s.px}px</td>
                        <td className="px-[14px] py-[9px] font-mono text-[var(--field-supporting)]">{s.fs}px</td>
                        <td className="px-[14px] py-[9px] text-[var(--field-supporting)]">{s.chars === 1 ? "1 char" : "2 chars"}</td>
                        <td className="px-[14px] py-[9px] text-[var(--field-supporting)]">{s.desc}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </section>

            {/* Color token table */}
            <section className="flex flex-col gap-[12px]">
              <h2 className="text-[13px] font-semibold uppercase tracking-[0.06em] text-[var(--field-supporting)]">Color tokens</h2>
              <p className="text-[12px] text-[var(--field-supporting)]">
                All tokens follow the pattern <code className="bg-[var(--code-bg)] px-[5px] py-[1px] rounded-[4px]">--av-col-{"{color}"}-bg</code>. Colors are darker in light mode to maintain white-text contrast (WCAG AA).
              </p>
              <div className="rounded-[8px] overflow-hidden" style={{ border: "1px solid var(--table-border)" }}>
                <table className="w-full text-[12px]">
                  <thead>
                    <tr style={{ background: "var(--table-header-bg)", borderBottom: "1px solid var(--table-border)" }}>
                      {["Color", "Token", "Dark mode", "Light mode"].map(h => (
                        <th key={h} className="text-left px-[14px] py-[10px] font-semibold text-[var(--field-supporting)]">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {([
                      ["blue",      "--av-col-blue-bg",      "#2173ff", "#1a5fd4"],
                      ["green",     "--av-col-green-bg",     "#059669", "#047857"],
                      ["red",       "--av-col-red-bg",       "#dc2626", "#b91c1c"],
                      ["orange",    "--av-col-orange-bg",    "#c2410c", "#9a3412"],
                      ["purple",    "--av-col-purple-bg",    "#7c3aed", "#6d28d9"],
                      ["limegreen", "--av-col-limegreen-bg", "#4d7c0f", "#3f6212"],
                      ["lightblue", "--av-col-lightblue-bg", "#0284c7", "#0369a1"],
                    ] as const).map(([color, token, dark, light], i, arr) => (
                      <tr key={color} style={{ borderBottom: i < arr.length - 1 ? "1px solid var(--table-border)" : "none" }}>
                        <td className="px-[14px] py-[9px]">
                          <div className="flex items-center gap-[8px]">
                            <div style={{ width: 20, height: 20, borderRadius: "50%", background: `var(--av-col-${color}-bg)`, flexShrink: 0 }} />
                            <span className="font-medium text-[var(--foreground)]">{color}</span>
                          </div>
                        </td>
                        <td className="px-[14px] py-[9px] font-mono text-[var(--field-supporting)]">{token}</td>
                        <td className="px-[14px] py-[9px] font-mono text-[var(--field-supporting)]">{dark}</td>
                        <td className="px-[14px] py-[9px] font-mono text-[var(--field-supporting)]">{light}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </section>

            {/* Usage */}
            <section className="flex flex-col gap-[12px]">
              <h2 className="text-[13px] font-semibold uppercase tracking-[0.06em] text-[var(--field-supporting)]">Usage</h2>
              <div className="rounded-[8px] p-[16px] font-mono text-[12px] leading-[1.8]"
                style={{ background: "var(--surface-raised)", border: "1px solid var(--table-border)", color: "var(--field-supporting)" }}>
                <span style={{ color: "#c792ea" }}>import</span>{" "}
                {"{ AvatarCircle } "}<span style={{ color: "#c792ea" }}>from</span>{" "}
                <span style={{ color: "#c3e88d" }}>"@/components/ui/avatar"</span><br /><br />
                <span style={{ color: "#697098" }}>{"// Auto color from name hash"}</span><br />
                {"<"}<span style={{ color: "#82aaff" }}>AvatarCircle</span>{" "}<span style={{ color: "#c792ea" }}>name</span>=<span style={{ color: "#c3e88d" }}>"Sarah Chen"</span>{" />"}<br /><br />
                <span style={{ color: "#697098" }}>{"// Explicit color override"}</span><br />
                {"<"}<span style={{ color: "#82aaff" }}>AvatarCircle</span>{" "}<span style={{ color: "#c792ea" }}>name</span>=<span style={{ color: "#c3e88d" }}>"Marco Rivera"</span>{" "}<span style={{ color: "#c792ea" }}>colorKey</span>=<span style={{ color: "#c3e88d" }}>"orange"</span>{" />"}<br /><br />
                <span style={{ color: "#697098" }}>{"// Size + selected state"}</span><br />
                {"<"}<span style={{ color: "#82aaff" }}>AvatarCircle</span>{" "}<span style={{ color: "#c792ea" }}>name</span>=<span style={{ color: "#c3e88d" }}>"Aisha Johnson"</span>{" "}<span style={{ color: "#c792ea" }}>sizeKey</span>=<span style={{ color: "#c3e88d" }}>"lg"</span>{" "}<span style={{ color: "#c792ea" }}>selected</span>{" />"}
              </div>
            </section>
          </div>
        )}

      </div>
    </div>
  )
}

// ── Icons Page ────────────────────────────────────────────────────────────

const ICON_TOTAL = ICON_CATEGORIES.reduce((n, c) => n + c.icons.length, 0)

// ── Highlight Icon Page ───────────────────────────────────────────────────

const HI_VARIANTS: HighlightIconVariant[] = [
  "informative","success","alert","error","neutral","yellow","lime","purple","light-blue"
]
const HI_VARIANT_ICONS: Record<HighlightIconVariant, string> = {
  informative:  "Zap",
  success:      "CheckCircle",
  alert:        "AlertTriangle",
  error:        "XCircle",
  neutral:      "Settings",
  yellow:       "Star",
  lime:         "Leaf",
  purple:       "Sparkles",
  "light-blue": "Cloud",
}

// ── Select page ────────────────────────────────────────────────────────────

const SELECT_OPTIONS = [
  "Claude Sonnet 4.5",
  "Claude Haiku 4.5",
  "Claude Opus 4",
  "GPT-4o",
  "Gemini 1.5 Pro",
]

// ── EmptyStatePage ─────────────────────────────────────────────────────────

const EMPTY_STATE_DEMOS: {
  label: string
  icon?: keyof typeof LucideIcons
  title: string
  description: string
  ctaLabel?: string
  cta2Label?: string
  showIcon?: boolean
  note: string
}[] = [
  {
    label: "Default — icon + CTA",
    icon: "Inbox",
    title: "No messages yet",
    description: "Messages from your team and notifications will appear here once activity begins.",
    ctaLabel: "Start a conversation",
    showIcon: true,
    note: "Standard usage: icon highlight + title + description + primary CTA",
  },
  {
    label: "Two CTAs",
    icon: "Users",
    title: "No contacts yet",
    description: "Add your first contact or import an existing list to get started.",
    ctaLabel: "Add contact",
    cta2Label: "Import list",
    showIcon: true,
    note: "When there are two actions available: secondary appears first (left), primary last (right)",
  },
  {
    label: "Search / filter — no results",
    icon: "SearchX",
    title: "No results found",
    description: "Try adjusting your filters or search terms to find what you're looking for.",
    ctaLabel: "Clear filters",
    showIcon: true,
    note: "After a search or filter returns 0 items. CTA clears/resets the active filter state",
  },
  {
    label: "Compact — inside table or card (no icon)",
    title: "No data available",
    description: "Run a workflow to start seeing results here.",
    showIcon: false,
    note: "Use inside <Table> or <CardContainer> — set className='py-[40px] rounded-none' and showIcon=false",
  },
]

const PG_ICONS: { label: string; key: string }[] = [
  { label: "Inbox",        key: "Inbox"      },
  { label: "Search off",   key: "SearchX"    },
  { label: "Users",        key: "Users"      },
  { label: "Folder",       key: "Folder"     },
  { label: "Database",     key: "Database"   },
  { label: "Bell off",     key: "BellOff"    },
  { label: "Star",         key: "Star"       },
  { label: "Activity",     key: "Activity"   },
]

function EmptyStatePage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab, setTab] = useState<"overview" | "playground" | "usage" | "reference">("overview")

  // Playground state
  const [pgShowIcon,    setPgShowIcon]    = useState(true)
  const [pgIconKey,     setPgIconKey]     = useState("Inbox")
  const [pgTitle,       setPgTitle]       = useState("No messages yet")
  const [pgDescription, setPgDescription] = useState("Messages from your team will appear here once activity begins.")
  const [pgShowCta,     setPgShowCta]     = useState(true)
  const [pgCtaLabel,    setPgCtaLabel]    = useState("Start a conversation")
  const [pgShowCta2,    setPgShowCta2]    = useState(false)
  const [pgCta2Label,   setPgCta2Label]   = useState("Learn more")
  const pgIcon = (LucideIcons as unknown as Record<string, LucideIcon>)[pgIconKey] as LucideIcon

  return (
    <div className="flex flex-col gap-0">
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Empty State</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px]">
            Zero-content placeholder for lists, tables, and views. Communicates absence and guides users toward the next action.
            Anatomy: Icon Highlight → Title → Description → 1–2 CTA buttons.
          </p>
        </div>
        <div className="flex items-center gap-[8px] shrink-0">
          <SpecButton onClick={() => openSpec("empty-state")} />
          <FigmaLink href="https://www.figma.com/design/v6rmYKA2zmyXWOahlxLOeI/Design-System---AIMS-OS?node-id=8419-24544" />
        </div>
      </div>

      <TabBar
        tabs={[
          { id: "overview",   label: "Overview"   },
          { id: "playground", label: "Playground" },
          { id: "usage",      label: "Usage"      },
          { id: "reference",  label: "Reference"  },
        ]}
        active={tab}
        onChange={id => setTab(id as typeof tab)}
      />

      <div className="flex flex-col gap-[40px] pt-[32px]">

        {/* ── Playground ────────────────────────────────────────────────── */}
        {tab === "playground" && (
          <div className="flex flex-col gap-[24px]">
            <div className="grid grid-cols-[300px_1fr] gap-[24px] items-start">

              {/* Controls panel */}
              <div className="flex flex-col gap-[20px] p-[20px] rounded-[10px] sticky top-[24px]"
                style={{ border: "1px solid var(--field-border)", background: "var(--field-bg)" }}>
                <p className="text-[12px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Controls</p>

                {/* Icon toggle + selector */}
                <div className="flex flex-col gap-[8px]">
                  <div className="flex items-center justify-between">
                    <label className="text-[13px] font-medium text-[var(--foreground)]">Show icon</label>
                    <Toggle checked={pgShowIcon} onChange={setPgShowIcon} size="sm" />
                  </div>
                  {pgShowIcon && (
                    <div className="flex flex-wrap gap-[6px] mt-[4px]">
                      {PG_ICONS.map(ic => (
                        <button
                          key={ic.key}
                          onClick={() => setPgIconKey(ic.key)}
                          title={ic.label}
                          className="w-[36px] h-[36px] flex items-center justify-center rounded-[6px] transition-all"
                          style={{
                            background: pgIconKey === ic.key ? "var(--card-primary-bg)" : "var(--field-bg-hover)",
                            border: `1.5px solid ${pgIconKey === ic.key ? "var(--primary)" : "var(--field-border)"}`,
                            color: pgIconKey === ic.key ? "var(--primary)" : "var(--field-supporting)",
                          }}
                        >
                          {(() => { const I = (LucideIcons as unknown as Record<string, LucideIcon>)[ic.key] as LucideIcon; return <I size={16} strokeWidth={1.75} /> })()}
                        </button>
                      ))}
                    </div>
                  )}
                </div>

                {/* Title */}
                <div className="flex flex-col gap-[6px]">
                  <label className="text-[13px] font-medium text-[var(--foreground)]">Title</label>
                  <Input
                    value={pgTitle}
                    onChange={e => setPgTitle(e.target.value)}
                    placeholder="No messages yet"
                    size="sm"
                  />
                </div>

                {/* Description */}
                <div className="flex flex-col gap-[6px]">
                  <label className="text-[13px] font-medium text-[var(--foreground)]">Description</label>
                  <textarea
                    value={pgDescription}
                    onChange={e => setPgDescription(e.target.value)}
                    placeholder="Supporting text…"
                    rows={3}
                    className="w-full text-[13px] font-medium rounded-[6px] px-[10px] py-[8px] resize-none focus:outline-none"
                    style={{
                      background: "var(--field-bg-hover)",
                      border: "1px solid var(--field-border)",
                      color: "var(--foreground)",
                    }}
                  />
                </div>

                {/* Primary CTA */}
                <div className="flex flex-col gap-[6px]">
                  <div className="flex items-center justify-between">
                    <label className="text-[13px] font-medium text-[var(--foreground)]">Primary CTA</label>
                    <Toggle checked={pgShowCta} onChange={setPgShowCta} size="sm" />
                  </div>
                  {pgShowCta && (
                    <Input
                      value={pgCtaLabel}
                      onChange={e => setPgCtaLabel(e.target.value)}
                      placeholder="Button label"
                      size="sm"
                    />
                  )}
                </div>

                {/* Secondary CTA */}
                <div className="flex flex-col gap-[6px]">
                  <div className="flex items-center justify-between">
                    <label className="text-[13px] font-medium text-[var(--foreground)]">Secondary CTA</label>
                    <Toggle checked={pgShowCta2} onChange={setPgShowCta2} size="sm" />
                  </div>
                  {pgShowCta2 && (
                    <Input
                      value={pgCta2Label}
                      onChange={e => setPgCta2Label(e.target.value)}
                      placeholder="Button label"
                      size="sm"
                    />
                  )}
                </div>
              </div>

              {/* Live preview */}
              <div
                className="flex items-center justify-center rounded-[12px] min-h-[360px]"
                style={{ border: "1px solid var(--field-border)", background: "var(--field-bg)" }}
              >
                <EmptyState
                  icon={pgIcon}
                  showIcon={pgShowIcon}
                  title={pgTitle || "Title"}
                  description={pgDescription || undefined}
                  ctaLabel={pgShowCta ? pgCtaLabel : undefined}
                  cta2Label={pgShowCta2 ? pgCta2Label : undefined}
                  className="py-[48px]"
                />
              </div>
            </div>
          </div>
        )}

        {/* ── Overview ──────────────────────────────────────────────────── */}
        {tab === "overview" && (
          <div className="flex flex-col gap-[32px]">

            {/* Visual demos */}
            {EMPTY_STATE_DEMOS.map((demo, i) => (
              <div key={i} className="flex flex-col gap-[12px]">
                <div className="flex items-start justify-between gap-[12px]">
                  <div>
                    <h2 className="text-[16px] font-semibold text-[var(--foreground)]">{demo.label}</h2>
                    <p className="text-[12px] text-[var(--field-supporting)] mt-[2px]">{demo.note}</p>
                  </div>
                </div>
                <div
                  className="rounded-[12px] overflow-hidden"
                  style={{ border: "1px solid var(--field-border)", background: "var(--field-bg)" }}
                >
                  <EmptyState
                    icon={demo.icon ? (LucideIcons as unknown as Record<string, LucideIcon>)[demo.icon] as LucideIcon : undefined}
                    showIcon={demo.showIcon}
                    title={demo.title}
                    description={demo.description}
                    ctaLabel={demo.ctaLabel}
                    cta2Label={demo.cta2Label}
                    className={demo.showIcon === false ? "py-[40px] rounded-none" : undefined}
                  />
                </div>
              </div>
            ))}

            {/* Inside a Table demo */}
            <div className="flex flex-col gap-[12px]">
              <div>
                <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Inside a Table</h2>
                <p className="text-[12px] text-[var(--field-supporting)] mt-[2px]">
                  Pass <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">emptyTitle</code>, <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">emptyDescription</code>, and <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">emptyIcon</code> directly to the <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">Table</code> component.
                </p>
              </div>
              <Table
                columns={[
                  { key: "name",   header: "Name" },
                  { key: "status", header: "Status" },
                  { key: "date",   header: "Last updated" },
                ]}
                data={[]}
                emptyIcon={(LucideIcons as unknown as Record<string, LucideIcon>)["SearchX"] as LucideIcon}
                emptyTitle="No records found"
                emptyDescription="Try adjusting your search or filters to see results."
                emptyCtaLabel="Clear filters"
              />
            </div>

            {/* Dashed border with CardContainer */}
            <div className="flex flex-col gap-[12px]">
              <div>
                <h2 className="text-[16px] font-semibold text-[var(--foreground)]">With CardContainer — Dashed Border</h2>
                <p className="text-[12px] text-[var(--field-supporting)] mt-[2px]">
                  Wrap <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">{"<EmptyState>"}</code> inside{" "}
                  <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">{'<CardContainer variant="dashed" size="lg">'}</code>{" "}
                  whenever the empty state occupies a standalone card slot (e.g. a dashboard widget or a droppable zone). The card provides the dashed border, radius, and 24px padding — use <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">className="py-[32px]"</code> on EmptyState to keep vertical breathing room without double-padding.
                </p>
              </div>
              <div className="grid grid-cols-2 gap-[16px]">

                {/* Variant 1: icon + title + desc + CTA */}
                <CardContainer variant="dashed" size="lg">
                  <EmptyState
                    icon={LucideIcons.SearchX}
                    showIcon
                    title="No results found"
                    description="Try adjusting your search or filters."
                    ctaLabel="Clear filters"
                    className="py-[32px] px-0"
                  />
                </CardContainer>

                {/* Variant 2: no icon + title + desc + CTA */}
                <CardContainer variant="dashed" size="lg">
                  <EmptyState
                    showIcon={false}
                    title="No results found"
                    description="Try adjusting your search or filters."
                    ctaLabel="Clear filters"
                    className="py-[32px] px-0"
                  />
                </CardContainer>

                {/* Variant 3: icon + title + desc, no CTA */}
                <CardContainer variant="dashed" size="lg">
                  <EmptyState
                    icon={LucideIcons.Inbox}
                    showIcon
                    title="Nothing here yet"
                    description="Content will appear here once activity begins."
                    className="py-[32px] px-0"
                  />
                </CardContainer>

                {/* Variant 4: no icon, no CTA — text only */}
                <CardContainer variant="dashed" size="lg">
                  <EmptyState
                    showIcon={false}
                    title="Nothing here yet"
                    description="Content will appear here once activity begins."
                    className="py-[32px] px-0"
                  />
                </CardContainer>

              </div>
            </div>

          </div>
        )}

        {/* ── Usage ─────────────────────────────────────────────────────── */}
        {tab === "usage" && (
          <div className="flex flex-col gap-[24px]">
            <div
              className="rounded-[10px] p-[20px] flex flex-col gap-[16px]"
              style={{ border: "1px solid var(--field-border)", background: "var(--field-bg)" }}
            >
              <div className="flex flex-col gap-[6px]">
                <p className="text-[13px] font-semibold text-[var(--foreground)]">✅ When to use</p>
                {[
                  "A list, table, dashboard, or inbox has zero items to display.",
                  "A search or filter returns no results.",
                  "The user has not yet created any content in a new section.",
                  "A connection or data source is not yet configured.",
                ].map(t => (
                  <p key={t} className="text-[13px] text-[var(--field-supporting)]">• {t}</p>
                ))}
              </div>

              <div className="flex flex-col gap-[6px]">
                <p className="text-[13px] font-semibold text-[var(--foreground)]">📦 Dashed border variant</p>
                <p className="text-[13px] text-[var(--field-supporting)]">
                  When the empty state occupies a standalone card slot (dashboard widget, droppable zone, or a section that will eventually hold a single entity), wrap it in <code className="font-mono text-[11px] bg-[var(--code-bg)] px-[4px] py-[0.5px] rounded">{'<CardContainer variant="dashed" size="lg">'}</code>. The dashed border signals to the user that this area expects content. Do <em>not</em> use a dashed card inside a table or full-page list — use the default inline empty state there.
                </p>
                <div
                  className="mt-[8px] rounded-[8px] px-[14px] py-[12px] font-mono text-[12px] leading-[1.7] overflow-x-auto"
                  style={{ background: "var(--code-bg)", color: "var(--foreground)" }}
                >
                  {`<CardContainer variant="dashed" size="lg">\n  <EmptyState\n    icon={Inbox}\n    title="No messages yet"\n    description="Messages will appear here once activity begins."\n    ctaLabel="Start a conversation"\n    className="py-[32px] px-0"\n  />\n</CardContainer>`}
                </div>
              </div>
              <div className="flex flex-col gap-[6px]">
                <p className="text-[13px] font-semibold text-[var(--foreground)]">❌ When NOT to use</p>
                {[
                  "Content is loading — use a Skeleton component instead.",
                  "An error occurred — use an Alert Banner with a specific error message.",
                  "There is at least one item to show, even partially.",
                ].map(t => (
                  <p key={t} className="text-[13px] text-[var(--field-supporting)]">• {t}</p>
                ))}
              </div>
            </div>

            <div className="flex flex-col gap-[8px]">
              <h2 className="text-[14px] font-semibold text-[var(--foreground)]">Accessibility</h2>
              {[
                "Container has role=\"status\" and aria-live=\"polite\" so screen readers announce it when content changes.",
                "The icon is decorative — rendered with aria-hidden=\"true\".",
                "CTA button must have a descriptive label (e.g. \"Add your first contact\", not just \"Add\").",
                "Do not rely on color alone — the title and description must always accompany the icon.",
              ].map(t => (
                <p key={t} className="text-[13px] text-[var(--field-supporting)]">• {t}</p>
              ))}
            </div>
          </div>
        )}

        {/* ── Reference ─────────────────────────────────────────────────── */}
        {tab === "reference" && (
          <div className="flex flex-col gap-[16px]">
            <div className="rounded-lg overflow-hidden" style={{ border: "1px solid var(--table-border)" }}>
              <table className="w-full text-[12px]">
                <thead>
                  <tr style={{ background: "var(--table-header-bg)", borderBottom: "1px solid var(--table-border)" }}>
                    {["Prop","Type","Default","Notes"].map(h => (
                      <th key={h} className="text-left px-[12px] py-[8px] font-semibold text-[var(--field-label)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    { prop: "icon",         type: "LucideIcon",  def: "Inbox",   note: "Icon component to render inside the highlight container" },
                    { prop: "showIcon",     type: "boolean",     def: "true",    note: "Toggle the Icon Highlight on/off" },
                    { prop: "title",        type: "string",      def: "—",       note: "Required. Short, direct headline" },
                    { prop: "description",  type: "string",      def: "—",       note: "Supporting text, max ~440px wide" },
                    { prop: "ctaLabel",     type: "string",      def: "—",       note: "Primary CTA label. Renders a primary Button" },
                    { prop: "onCta",        type: "() => void",  def: "—",       note: "Primary CTA click handler" },
                    { prop: "cta2Label",    type: "string",      def: "—",       note: "Secondary CTA label (shown to the left of primary)" },
                    { prop: "onCta2",       type: "() => void",  def: "—",       note: "Secondary CTA click handler" },
                    { prop: "className",    type: "string",      def: "—",       note: "Compact: 'py-[40px] rounded-none'" },
                  ].map((r, i) => (
                    <tr key={r.prop} style={{ background: i % 2 === 1 ? "var(--row-alt-bg)" : undefined }}>
                      <td className="px-[12px] py-[8px] font-mono text-[11px] text-[#2173ff]">{r.prop}</td>
                      <td className="px-[12px] py-[8px] font-mono text-[11px] text-[var(--field-supporting)]">{r.type}</td>
                      <td className="px-[12px] py-[8px] font-mono text-[11px] text-[var(--field-label)]">{r.def}</td>
                      <td className="px-[12px] py-[8px] text-[var(--field-supporting)]">{r.note}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Token reference */}
            <h2 className="text-[14px] font-semibold text-[var(--foreground)] mt-[8px]">CSS Variables</h2>
            <div className="rounded-[8px] p-[16px] font-mono text-[12px] leading-[1.8]" style={{ background: "var(--code-bg)", border: "1px solid var(--field-border)" }}>
              <p className="text-[var(--field-supporting)]">{"/* Icon Highlight — Surface/Primary/More Subtle */"}</p>
              <p><span className="text-[var(--primary)]">--card-primary-bg</span><span className="text-[var(--field-supporting)]">:  #f6f9ff {"/* light */"} | rgba(43,127,255,0.08) {"/* dark */"}</span></p>
              <p><span className="text-[var(--primary)]">--primary</span><span className="text-[var(--field-supporting)]">:          #2173ff {"/* light */"} | #2b7fff {"/* dark */"}</span></p>
              <p className="mt-[8px] text-[var(--field-supporting)]">{"/* Typography — Text/Title · Text/Body */"}</p>
              <p><span className="text-[var(--primary)]">--foreground</span><span className="text-[var(--field-supporting)]">:       Title → Text/Title</span></p>
              <p><span className="text-[var(--primary)]">--field-supporting</span><span className="text-[var(--field-supporting)]">: Description → Text/Body</span></p>
              <p className="mt-[8px] text-[var(--field-supporting)]">{"/* CTA Buttons — delegated to Button component */"}</p>
              <p><span className="text-[var(--primary)]">--btn-primary-*</span><span className="text-[var(--field-supporting)]">:   Primary CTA (Surface/Primary/Default)</span></p>
              <p><span className="text-[var(--primary)]">--btn-secondary-*</span><span className="text-[var(--field-supporting)]">: Secondary CTA (Surface/Neutral/White)</span></p>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

function SelectPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab,         setTab]         = useState<"overview" | "playground" | "reference">("overview")
  const [selState,    setSelState]    = useState<SelectState>("default")
  const [selSize,     setSelSize]     = useState<"default" | "sm">("default")
  const [showLabel,   setShowLabel]   = useState(true)
  const [showSupport, setShowSupport] = useState(true)
  const [showIcon,    setShowIcon]    = useState(false)

  // Playground interactive state
  const [pgOpen,  setPgOpen]  = useState(false)
  const [pgValue, setPgValue] = useState("")

  const pgSupportText =
    selState === "error"    ? "Please select a model to continue" :
    showSupport             ? "Choose the model for this node"    : undefined

  return (
    <div className="flex flex-col gap-0">
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Select</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px]">
            Non-editable trigger field that opens a Menu/Dropdown panel. Shares the same visual shell
            as Input — border, label, supporting text, icon slots — but the right icon is always
            dynamic: ChevronDown, ChevronUp (open), or × (has value).
          </p>
        </div>
        <SpecButton onClick={() => openSpec("select")} />
      </div>

      <TabBar
        tabs={[
          { id: "overview",   label: "Overview"   },
          { id: "playground", label: "Playground" },
          { id: "reference",  label: "Reference"  },
        ]}
        active={tab}
        onChange={id => setTab(id as typeof tab)}
      />

      <div className="flex flex-col gap-[40px] pt-[32px]">

        {/* ── Overview ───────────────────────────────────────────────── */}
        {tab === "overview" && (
          <div className="flex flex-col gap-[24px]">
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Anatomy</h2>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[24px] flex flex-col gap-[20px]">
                <div className="flex flex-wrap gap-[24px] items-end">
                  {/* Default — no value */}
                  <div className="flex flex-col gap-[8px]">
                    <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Default · no value</p>
                    <div className="w-[240px]">
                      <Select label="AI Model" placeholder="Select an option" supportingText="Choose the model for this node" />
                    </div>
                  </div>
                  {/* Has value */}
                  <div className="flex flex-col gap-[8px]">
                    <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Has value (selected)</p>
                    <div className="w-[240px]">
                      <Select label="AI Model" value="Claude Sonnet 4.5" supportingText="Choose the model for this node" />
                    </div>
                  </div>
                  {/* Open */}
                  <div className="flex flex-col gap-[8px]">
                    <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Open (dropdown visible)</p>
                    <div className="w-[240px]">
                      <Select label="AI Model" placeholder="Select an option" open supportingText="Choose the model for this node" />
                    </div>
                  </div>
                </div>
                <div className="flex flex-wrap gap-[24px] items-end">
                  {/* Error */}
                  <div className="flex flex-col gap-[8px]">
                    <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Error</p>
                    <div className="w-[240px]">
                      <Select label="AI Model" placeholder="Select an option" state="error" supportingText="Please select a model to continue" />
                    </div>
                  </div>
                  {/* Disabled */}
                  <div className="flex flex-col gap-[8px]">
                    <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">Disabled</p>
                    <div className="w-[240px]">
                      <Select label="AI Model" placeholder="Select an option" state="disabled" supportingText="Fixed by workflow configuration" />
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Right icon logic</h2>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[16px] flex flex-col gap-0 divide-y divide-[var(--field-border)]">
                {[
                  { condition: "open = true",                          icon: "ChevronUp",   note: "Regardless of value" },
                  { condition: "open = false · value exists",          icon: "X (clear)",   note: "Blue border — click to clear value" },
                  { condition: "open = false · no value · state=error",icon: "CircleAlert", note: "Red border" },
                  { condition: "open = false · no value · default",    icon: "ChevronDown", note: "Gray border" },
                ].map(r => (
                  <div key={r.condition} className="flex items-center justify-between py-[10px] gap-[12px]">
                    <code className="text-[12px] font-mono text-[var(--foreground)]">{r.condition}</code>
                    <div className="flex items-center gap-[8px]">
                      <span className="text-[12px] font-semibold text-[var(--field-border-focus)] bg-[var(--field-bg)] border border-[var(--field-border)] rounded px-[6px] py-[2px]">
                        {r.icon}
                      </span>
                      <span className="text-[12px] text-[var(--field-supporting)]">{r.note}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ── Playground ─────────────────────────────────────────────── */}
        {tab === "playground" && (
          <div className="flex flex-col gap-[20px]">
            <div className="rounded-md border border-[var(--field-border)] p-[20px] flex flex-col gap-[16px]">
              <CtrlGroup
                label="State"
                options={[{label:"Default",value:"default"},{label:"Error",value:"error"},{label:"Disabled",value:"disabled"}]}
                value={selState}
                onChange={v => setSelState(v as SelectState)}
              />
              <CtrlGroup
                label="Size"
                options={[{label:"S — 32px",value:"sm"},{label:"M — 40px",value:"default"}]}
                value={selSize}
                onChange={v => setSelSize(v as "default" | "sm")}
              />
              <CtrlToggle label="Label"      value={showLabel}   onChange={setShowLabel} />
              <CtrlToggle label="Supporting" value={showSupport} onChange={setShowSupport} />
              <CtrlToggle label="Left icon"  value={showIcon}    onChange={setShowIcon} />
            </div>

            {/* Interactive preview */}
            <div className="flex flex-col items-center gap-[12px] min-h-[260px] rounded-md border border-[var(--field-border)] border-dashed px-[40px] py-[24px]">
              <div className="w-full max-w-[320px] relative">
                <Select
                  state={selState}
                  size={selSize}
                  label={showLabel ? "AI Model" : undefined}
                  supportingText={pgSupportText}
                  leadingIcon={showIcon ? <SearchIcon /> : undefined}
                  placeholder="Select an option"
                  value={pgValue}
                  open={pgOpen}
                  onClick={() => selState !== "disabled" && setPgOpen(o => !o)}
                  onClear={() => { setPgValue(""); setPgOpen(false) }}
                />
                {pgOpen && selState !== "disabled" && (
                  <div className="absolute top-[calc(100%+4px)] left-0 right-0 z-[50]">
                    <Menu className="w-full">
                      {SELECT_OPTIONS.map(opt => (
                        <MenuItem
                          key={opt}
                          label={opt}
                          state={opt === pgValue ? "focus" : "default"}
                          onClick={() => { setPgValue(opt); setPgOpen(false) }}
                        />
                      ))}
                    </Menu>
                  </div>
                )}
              </div>
              {pgValue && (
                <p className="text-[12px] text-[var(--field-supporting)]">
                  Selected: <strong className="text-[var(--foreground)]">{pgValue}</strong>
                </p>
              )}
            </div>
          </div>
        )}

        {/* ── Reference ──────────────────────────────────────────────── */}
        {tab === "reference" && (
          <div className="flex flex-col gap-[24px]">

            <Row label="1 · All states — no value">
              {(["default","error","disabled"] as SelectState[]).map(s => (
                <div key={s} className="w-[220px]">
                  <Select
                    label="AI Model"
                    placeholder="Select an option"
                    state={s}
                    supportingText={s === "error" ? "Please select a model" : s === "disabled" ? "Fixed by configuration" : "Choose the model"}
                  />
                </div>
              ))}
            </Row>

            <Row label="2 · Has value selected (blue border · × clear)">
              <div className="w-[220px]">
                <Select label="AI Model" value="Claude Sonnet 4.5" supportingText="Model confirmed" />
              </div>
              <div className="w-[220px]">
                <Select label="Environment" value="Production" supportingText="Active environment" />
              </div>
              <div className="w-[220px]">
                <Select label="Region" value="us-east-1" supportingText="AWS region" />
              </div>
            </Row>

            <Row label="3 · Open state (ChevronUp · blue border)">
              <div className="w-[220px]">
                <Select label="AI Model" placeholder="Select an option" open supportingText="Choose the model" />
              </div>
              <div className="w-[220px]">
                <Select label="AI Model" value="Claude Haiku 4.5" open supportingText="Choose the model" />
              </div>
            </Row>

            <Row label="4 · Sizes — S (32px) / M (40px)">
              <div className="w-[220px]">
                <Select size="sm"      label="Model" placeholder="Select..." />
              </div>
              <div className="w-[220px]">
                <Select size="default" label="Model" placeholder="Select..." />
              </div>
            </Row>

            <Row label="5 · With leading icon">
              <div className="w-[240px]">
                <Select
                  label="AI Model"
                  placeholder="Select a model"
                  leadingIcon={<SearchIcon />}
                  supportingText="Search or select"
                />
              </div>
              <div className="w-[240px]">
                <Select
                  label="AI Model"
                  value="Claude Sonnet 4.5"
                  leadingIcon={<SearchIcon />}
                  supportingText="Model confirmed"
                />
              </div>
            </Row>

            <Row label="6 · Without label">
              <div className="w-[200px]"><Select placeholder="Select an option" /></div>
              <div className="w-[200px]"><Select placeholder="Select an option" state="error" supportingText="Required field" /></div>
              <div className="w-[200px]"><Select value="Claude Sonnet" /></div>
            </Row>

            <Row label="7 · Select + Menu (composed pattern)">
              <div className="w-[260px] relative" style={{ height: "auto" }}>
                <p className="text-[12px] text-[var(--field-supporting)] mb-[8px]">
                  Select is a trigger only — compose with&nbsp;
                  <code className="text-[var(--foreground)]">&lt;Menu&gt;</code> for the full dropdown.
                </p>
                <Select label="AI Model" value="Claude Haiku 4.5" open />
                <div className="mt-[4px]">
                  <Menu className="w-full">
                    <MenuSection label="Anthropic" />
                    {["Claude Sonnet 4.5","Claude Haiku 4.5","Claude Opus 4"].map(opt => (
                      <MenuItem key={opt} label={opt} state={opt === "Claude Haiku 4.5" ? "focus" : "default"} />
                    ))}
                    <MenuDivider />
                    <MenuSection label="Other" />
                    {["GPT-4o","Gemini 1.5 Pro"].map(opt => (
                      <MenuItem key={opt} label={opt} />
                    ))}
                  </Menu>
                </div>
              </div>
            </Row>

          </div>
        )}
      </div>
    </div>
  )
}

// ── Checkbox page ──────────────────────────────────────────────────────────

function CheckboxPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab,        setTab]       = useState<"overview" | "playground" | "reference">("overview")
  const [cbSize,     setCbSize]    = useState<"default" | "sm">("default")
  const [cbChecked,  setCbChecked] = useState(false)
  const [cbDisabled, setCbDisabled]= useState(false)
  const [showLabel,  setShowLabel] = useState(false)
  const [showDesc,   setShowDesc]  = useState(false)

  // Reference — group states
  const [refChecks, setRefChecks]  = useState<boolean[]>([false, true, false, true, false])

  return (
    <div className="flex flex-col gap-0">
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Checkbox</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px]">
            Binary selection control for forms, tables, and lists. The outer circular area is a ripple
            zone — it provides hover/focus feedback without affecting layout. 2 sizes, 4 interaction states.
          </p>
        </div>
        <SpecButton onClick={() => openSpec("checkbox")} />
      </div>

      <TabBar
        tabs={[
          { id: "overview",   label: "Overview"   },
          { id: "playground", label: "Playground" },
          { id: "reference",  label: "Reference"  },
        ]}
        active={tab}
        onChange={id => setTab(id as typeof tab)}
      />

      <div className="flex flex-col gap-[40px] pt-[32px]">

        {/* ── Overview ─────────────────────────────────────────────── */}
        {tab === "overview" && (
          <div className="flex flex-col gap-[24px]">
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Anatomy</h2>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[24px] flex flex-wrap gap-[32px] items-end">
                {(["default","sm"] as const).map(s => (
                  <div key={s} className="flex flex-col gap-[8px] items-start">
                    <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">
                      Size {s === "default" ? "M (32×32)" : "S (24×24)"}
                    </p>
                    <div className="flex gap-[16px] items-center">
                      <div className="flex flex-col gap-[4px] items-center">
                        <Checkbox size={s} checked={false} />
                        <p className="text-[11px] text-[var(--field-supporting)]">unchecked</p>
                      </div>
                      <div className="flex flex-col gap-[4px] items-center">
                        <Checkbox size={s} checked={true} />
                        <p className="text-[11px] text-[var(--field-supporting)]">checked</p>
                      </div>
                      <div className="flex flex-col gap-[4px] items-center">
                        <Checkbox size={s} checked={false} disabled />
                        <p className="text-[11px] text-[var(--field-supporting)]">disabled</p>
                      </div>
                      <div className="flex flex-col gap-[4px] items-center">
                        <Checkbox size={s} checked={true} disabled />
                        <p className="text-[11px] text-[var(--field-supporting)]">checked+dis</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">With label</h2>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px] flex flex-col gap-[12px]">
                <Checkbox label="Enable notifications" />
                <Checkbox label="Send weekly digest" description="Receive a summary of activity every Monday morning" />
                <Checkbox label="Allow data sharing" description="Share anonymized usage data to help improve the product" checked />
                <Checkbox label="This option is unavailable" description="Contact your admin to enable this feature" disabled />
              </div>
            </div>
          </div>
        )}

        {/* ── Playground ───────────────────────────────────────────── */}
        {tab === "playground" && (
          <div className="flex flex-col gap-[20px]">
            <div className="rounded-md border border-[var(--field-border)] p-[20px] flex flex-col gap-[16px]">
              <CtrlGroup
                label="Size"
                options={[{label:"M — 32px",value:"default"},{label:"S — 24px",value:"sm"}]}
                value={cbSize}
                onChange={v => setCbSize(v as "default" | "sm")}
              />
              <CtrlToggle label="Checked"   value={cbChecked}  onChange={setCbChecked} />
              <CtrlToggle label="Disabled"  value={cbDisabled} onChange={setCbDisabled} />
              <CtrlToggle label="Label"     value={showLabel}  onChange={setShowLabel} />
              <CtrlToggle label="Desc"      value={showDesc}   onChange={v => { setShowDesc(v); if (v) setShowLabel(true) }} />
            </div>
            <div className="flex items-center justify-center min-h-[100px] rounded-md border border-[var(--field-border)] border-dashed px-[40px]">
              <Checkbox
                size={cbSize}
                checked={cbChecked}
                disabled={cbDisabled}
                onChange={setCbChecked}
                label={showLabel ? "Enable this option" : undefined}
                description={showDesc ? "Toggle to activate this setting for your workspace" : undefined}
              />
            </div>
          </div>
        )}

        {/* ── Reference ────────────────────────────────────────────── */}
        {tab === "reference" && (
          <div className="flex flex-col gap-[24px]">
            <Row label="1 · All states — Size M">
              <div className="flex gap-[16px] items-center flex-wrap">
                {[
                  { checked: false, disabled: false, label: "Unchecked" },
                  { checked: true,  disabled: false, label: "Checked"   },
                  { checked: false, disabled: true,  label: "Disabled"  },
                  { checked: true,  disabled: true,  label: "Dis+checked"},
                ].map(c => (
                  <div key={c.label} className="flex flex-col gap-[8px] items-center">
                    <Checkbox checked={c.checked} disabled={c.disabled} />
                    <p className="text-[11px] text-[var(--field-supporting)]">{c.label}</p>
                  </div>
                ))}
              </div>
            </Row>

            <Row label="2 · Sizes — S / M">
              <div className="flex gap-[24px] items-center">
                <div className="flex flex-col gap-[4px] items-center">
                  <Checkbox size="sm"      checked={true} />
                  <p className="text-[11px] text-[var(--field-supporting)]">S — 24×24</p>
                </div>
                <div className="flex flex-col gap-[4px] items-center">
                  <Checkbox size="default" checked={true} />
                  <p className="text-[11px] text-[var(--field-supporting)]">M — 32×32</p>
                </div>
              </div>
            </Row>

            <Row label="3 · With label and description">
              <div className="flex flex-col gap-[10px]">
                <Checkbox label="Enable AI suggestions" description="Receive real-time suggestions powered by the selected model" />
                <Checkbox label="Auto-save drafts" description="Save workflow drafts every 30 seconds automatically" checked />
                <Checkbox label="Public visibility" description="Make this workflow visible to all workspace members" disabled />
              </div>
            </Row>

            <Row label="4 · Interactive list (click to toggle)">
              <div className="flex flex-col gap-[8px] w-[280px]">
                {["Claude Sonnet 4.5","Claude Haiku 4.5","GPT-4o","Gemini 1.5 Pro","Llama 3.1"].map((opt, i) => (
                  <Checkbox
                    key={opt}
                    checked={refChecks[i] ?? false}
                    onChange={v => setRefChecks(prev => { const n=[...prev]; n[i]=v; return n })}
                    label={opt}
                  />
                ))}
              </div>
            </Row>

            <Row label="5 · Used as Menu leading slot">
              <Menu>
                {["Include metadata","Compress output","Add timestamps","Verbose logging"].map((opt,i) => (
                  <MenuItem
                    key={opt}
                    label={opt}
                    checkbox={<Checkbox size="sm" checked={i===0||i===2} />}
                  />
                ))}
              </Menu>
            </Row>
          </div>
        )}
      </div>
    </div>
  )
}

// ── ChipPage ─────────────────────────────────────────────────────────────────

function ChipPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab,         setTab]         = useState<"overview" | "playground" | "reference">("overview")
  const [pgVariant,   setPgVariant]   = useState<ChipVariant>("primary")
  const [pgSize,      setPgSize]      = useState<ChipSize>("m")
  const [pgPersonIcon,setPgPersonIcon]= useState(false)
  const [pgDisabled,  setPgDisabled]  = useState(false)

  const ALL_VARIANTS: { variant: ChipVariant; label: string }[] = [
    { variant: "primary",            label: "Primary" },
    { variant: "secondary",          label: "Secondary" },
    { variant: "purple-primary",     label: "Purple Primary" },
    { variant: "purple-secondary",   label: "Purple Secondary" },
    { variant: "light-blue-primary", label: "Light Blue" },
  ]

  return (
    <div className="flex flex-col gap-0">
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Chip</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px]">
            Pill-shaped selection control for filtering and categorization. 5 color variants × 2 sizes × 4 states. Used in Slide Out filter rows and any category-selection surface.
          </p>
        </div>
        <SpecButton onClick={() => openSpec("chip")} />
      </div>

      <TabBar
        tabs={[
          { id: "overview",   label: "Overview"   },
          { id: "playground", label: "Playground" },
          { id: "reference",  label: "Reference"  },
        ]}
        active={tab}
        onChange={id => setTab(id as typeof tab)}
      />

      <div className="flex flex-col gap-[40px] pt-[32px]">

        {/* ── Overview ─────────────────────────────────────────────────── */}
        {tab === "overview" && (
          <div className="flex flex-col gap-[32px]">

            {/* Size M */}
            <div className="flex flex-col gap-[16px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Size M — 28px</h2>
              <div className="flex flex-wrap items-end gap-[20px]">
                {ALL_VARIANTS.map(({ variant, label }) => (
                  <div key={variant} className="flex flex-col items-center gap-[8px]">
                    <Chip variant={variant} size="m">{label}</Chip>
                    <span className="text-[11px] text-[var(--field-supporting)] text-center">{variant}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Size S */}
            <div className="flex flex-col gap-[16px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Size S — 20px</h2>
              <div className="flex flex-wrap items-end gap-[20px]">
                {ALL_VARIANTS.map(({ variant, label }) => (
                  <div key={variant} className="flex flex-col items-center gap-[8px]">
                    <Chip variant={variant} size="s">{label}</Chip>
                    <span className="text-[11px] text-[var(--field-supporting)] text-center">{variant}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Person icon */}
            <div className="flex flex-col gap-[16px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Person icon</h2>
              <div className="flex flex-wrap gap-[12px] items-center">
                <Chip variant="primary"   size="m" personIcon>Primary M</Chip>
                <Chip variant="secondary" size="m" personIcon>Secondary M</Chip>
                <Chip variant="primary"   size="s" personIcon>Primary S</Chip>
                <Chip variant="secondary" size="s" personIcon>Secondary S</Chip>
              </div>
            </div>

            {/* Disabled */}
            <div className="flex flex-col gap-[16px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Disabled state</h2>
              <div className="flex flex-wrap gap-[12px] items-center">
                {ALL_VARIANTS.map(({ variant, label }) => (
                  <Chip key={variant} variant={variant} size="m" disabled>{label}</Chip>
                ))}
              </div>
            </div>

            {/* Slide Out usage */}
            <div className="flex flex-col gap-[16px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">In context — Slide Out filter row (Size S)</h2>
              <div className="flex items-center gap-[8px] p-[12px] rounded-[8px]" style={{ background: "var(--surface-raised)" }}>
                {["All", "Category 1", "Category 2", "Category 3", "Category 4"].map((label, i) => (
                  <Chip key={i} variant={i === 0 ? "primary" : "secondary"} size="s">{label}</Chip>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ── Playground ───────────────────────────────────────────────── */}
        {tab === "playground" && (
          <div className="flex flex-col gap-[20px]">
            <div className="rounded-md border border-[var(--field-border)] p-[20px] flex flex-col gap-[16px]">
              <CtrlGroup
                label="Variant"
                options={ALL_VARIANTS.map(v => ({ label: v.label, value: v.variant }))}
                value={pgVariant}
                onChange={v => setPgVariant(v as ChipVariant)}
              />
              <CtrlGroup
                label="Size"
                options={[{ label: "M — 28px", value: "m" }, { label: "S — 20px", value: "s" }]}
                value={pgSize}
                onChange={v => setPgSize(v as ChipSize)}
              />
              <CtrlToggle label="Person icon" value={pgPersonIcon} onChange={setPgPersonIcon} />
              <CtrlToggle label="Disabled"    value={pgDisabled}   onChange={setPgDisabled} />
            </div>
            <div className="flex items-center justify-center min-h-[100px] rounded-md border border-dashed border-[var(--field-border)]">
              <Chip variant={pgVariant} size={pgSize} personIcon={pgPersonIcon} disabled={pgDisabled}>
                Label
              </Chip>
            </div>
          </div>
        )}

        {/* ── Reference ────────────────────────────────────────────────── */}
        {tab === "reference" && (
          <div className="flex flex-col gap-[32px]">

            {/* Tokens table */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Design tokens</h2>
              <div className="overflow-x-auto rounded-md border border-[var(--field-border)]">
                <table className="w-full text-[13px]">
                  <thead>
                    <tr style={{ background: "var(--table-header-bg)", borderBottom: "1px solid var(--field-border)" }}>
                      {["Token", "Role", "Dark", "Light"].map(h => (
                        <th key={h} className="text-left px-[12px] py-[8px] text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {[
                      { token: "--color-surface-primary-default",       role: "Primary BG (default)",           dark: "#2b7fff",                light: "#2173ff" },
                      { token: "--color-surface-primary-darker",        role: "Primary BG (hover)",             dark: "#001740",                light: "#001740" },
                      { token: "--color-surface-primary-lighter",       role: "Primary BG (disabled)",          dark: "#80afff",                light: "#80afff" },
                      { token: "--color-button-primary-text-default",   role: "Primary text / icon",            dark: "#ffffff",                light: "#ffffff" },
                      { token: "--color-button-primary-text-disabled",  role: "Primary text disabled",          dark: "rgba(255,255,255,0.30)", light: "#f2f2f2" },
                      { token: "--color-surface-neutral-white",         role: "Secondary BG (always white)",    dark: "#ffffff",                light: "#ffffff" },
                      { token: "--chip-secondary-text",                 role: "Secondary text",                 dark: "#5c5c5c",                light: "#8c8c8c" },
                      { token: "--chip-secondary-bg-hover",             role: "Secondary BG (hover)",           dark: "#f2f2f2",                light: "#f2f2f2" },
                      { token: "--color-border-neutral-default",        role: "Secondary border",               dark: "rgba(255,255,255,0.10)", light: "#5c5c5c" },
                      { token: "--color-surface-purple-default",        role: "Purple primary BG",              dark: "#7b27ed",                light: "#7b27ed" },
                      { token: "--color-text-purple",                   role: "Purple secondary text",          dark: "#2c075c",                light: "#2c075c" },
                      { token: "--color-border-purple-default",         role: "Purple secondary border",        dark: "#7b27ed",                light: "#7b27ed" },
                      { token: "--color-surface-light-blue-default",    role: "Light blue BG",                  dark: "#00b5d9",                light: "#00b5d9" },
                    ].map((row, i, arr) => (
                      <tr key={row.token} style={{ borderBottom: i < arr.length - 1 ? "1px solid var(--field-border)" : "none", background: i % 2 === 0 ? "transparent" : "var(--row-alt-bg)" }}>
                        <td className="px-[12px] py-[8px] font-mono text-[11px]" style={{ color: "var(--color-text-subtitle)" }}>{row.token}</td>
                        <td className="px-[12px] py-[8px] text-[var(--foreground)]">{row.role}</td>
                        <td className="px-[12px] py-[8px] font-mono text-[11px]" style={{ color: "var(--color-text-subtitle)" }}>{row.dark}</td>
                        <td className="px-[12px] py-[8px] font-mono text-[11px]" style={{ color: "var(--color-text-subtitle)" }}>{row.light}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Props table */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Props</h2>
              <div className="overflow-x-auto rounded-md border border-[var(--field-border)]">
                <table className="w-full text-[13px]">
                  <thead>
                    <tr style={{ background: "var(--table-header-bg)", borderBottom: "1px solid var(--field-border)" }}>
                      {["Prop", "Type", "Default", "Description"].map(h => (
                        <th key={h} className="text-left px-[12px] py-[8px] text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {[
                      { prop: "variant",    type: "ChipVariant",  def: '"secondary"', desc: "primary | secondary | purple-primary | purple-secondary | light-blue-primary" },
                      { prop: "size",       type: "ChipSize",     def: '"m"',         desc: "m = 28px height · s = 20px height. Both use 12px horizontal padding." },
                      { prop: "personIcon", type: "boolean",      def: "false",       desc: "Renders a User icon to the left of the label." },
                      { prop: "disabled",   type: "boolean",      def: "false",       desc: "Muted appearance, click blocked, aria-disabled set." },
                      { prop: "onClick",    type: "() => void",   def: "—",           desc: "Click handler. No-op when disabled." },
                      { prop: "className",  type: "string",       def: "—",           desc: "Appended to root element. Use for shrink-0 in flex rows." },
                    ].map((row, i, arr) => (
                      <tr key={row.prop} style={{ borderBottom: i < arr.length - 1 ? "1px solid var(--field-border)" : "none", background: i % 2 === 0 ? "transparent" : "var(--row-alt-bg)" }}>
                        <td className="px-[12px] py-[8px] font-mono text-[11px] font-semibold text-[var(--foreground)]">{row.prop}</td>
                        <td className="px-[12px] py-[8px] font-mono text-[11px]" style={{ color: "var(--color-text-subtitle)" }}>{row.type}</td>
                        <td className="px-[12px] py-[8px] font-mono text-[11px]" style={{ color: "var(--color-text-subtitle)" }}>{row.def}</td>
                        <td className="px-[12px] py-[8px]" style={{ color: "var(--field-supporting)" }}>{row.desc}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Code snippet */}
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">Usage</h2>
              <pre className="rounded-md p-[16px] text-[12px] leading-[20px] overflow-x-auto" style={{ background: "var(--code-bg)", color: "var(--foreground)" }}>{`import { Chip } from "@/components/ui/chip"

// Primary — active/selected state
<Chip variant="primary" size="m">All</Chip>

// Secondary — inactive/unselected
<Chip variant="secondary" size="s">Category 1</Chip>

// With person icon
<Chip variant="primary" size="m" personIcon>Assign</Chip>

// Disabled
<Chip variant="secondary" size="m" disabled>Unavailable</Chip>

// In a filter row (Slide Out pattern)
{chipLabels.map((label, i) => (
  <Chip
    key={i}
    variant={i === activeChip ? "primary" : "secondary"}
    size="s"
    className="shrink-0"
    onClick={() => setActiveChip(i)}
  >
    {label}
  </Chip>
))}`}
              </pre>
            </div>
          </div>
        )}

      </div>
    </div>
  )
}

// ── TooltipPage ───────────────────────────────────────────────────────────────

function TooltipPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  type PageTab = "overview" | "playground" | "reference"
  const [tab, setTab] = useState<PageTab>("overview")

  const [pgContent, setPgContent] = useState("Click to copy link")
  const [pgArrow,   setPgArrow]   = useState(false)
  const [pgSide,    setPgSide]    = useState<TooltipSide>("top")

  const tabItems = [
    { id: "overview",   label: "Overview" },
    { id: "playground", label: "Playground" },
    { id: "reference",  label: "Reference" },
  ]

  const codeSnippet = `import { Tooltip } from "@/components/ui/tooltip"

{/* Plain tooltip */}
<Tooltip content="Copy to clipboard">
  <button>Copy</button>
</Tooltip>

{/* With arrow, positioned below */}
<Tooltip content="More information" arrow side="bottom">
  <button>Info</button>
</Tooltip>`

  const demoSides: TooltipSide[] = ["top", "right", "bottom", "left"]

  return (
    <div className="flex flex-col gap-[32px]">
      {/* Header */}
      <div className="flex items-start justify-between gap-[16px]">
        <div className="flex flex-col gap-[8px]">
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Tooltip</h1>
          <p className="text-[14px] text-[var(--field-supporting)] max-w-[600px]">
            Small informational overlay appearing on hover or focus. Always dark regardless of theme mode.
            Two variants: plain (no arrow) and with directional arrow pointer.
            Maximum recommended width: 300px.
          </p>
        </div>
        <SpecButton onClick={() => openSpec("tooltip")} />
      </div>

      {/* Tabs */}
      <Tabs
        items={tabItems}
        activeId={tab}
        onChange={(id) => setTab(id as PageTab)}
      />

      {/* Overview */}
      {tab === "overview" && (
        <div className="flex flex-col gap-[40px]">

          {/* Plain variant */}
          <div className="flex flex-col gap-[16px]">
            <SectionLabel>Plain — no arrow (default)</SectionLabel>
            <div className="flex flex-wrap items-center gap-[32px] py-[40px] px-[32px]" style={{ background: "var(--surface)", borderRadius: 8, border: "0.5px solid var(--field-border)" }}>
              <Tooltip content="Copy to clipboard">
                <button className="px-[16px] py-[8px] rounded-[8px] text-[14px] font-medium text-[var(--foreground)] bg-[var(--field-bg)] border border-[var(--field-border)]">Copy link</button>
              </Tooltip>
              <Tooltip content="Remove this item from the list">
                <button className="px-[16px] py-[8px] rounded-[8px] text-[14px] font-medium text-[var(--foreground)] bg-[var(--field-bg)] border border-[var(--field-border)]">Delete</button>
              </Tooltip>
              <Tooltip content="Maximum recommended width is 300px. Content exceeding two lines should use ellipsis.">
                <button className="px-[16px] py-[8px] rounded-[8px] text-[14px] font-medium text-[var(--foreground)] bg-[var(--field-bg)] border border-[var(--field-border)]">Long tooltip text</button>
              </Tooltip>
            </div>
          </div>

          {/* Arrow variant — all 4 sides */}
          <div className="flex flex-col gap-[16px]">
            <SectionLabel>Arrow variant — 4 sides</SectionLabel>
            <div className="flex flex-wrap items-center justify-center gap-[48px] py-[56px] px-[32px]" style={{ background: "var(--surface)", borderRadius: 8, border: "0.5px solid var(--field-border)" }}>
              {demoSides.map(s => (
                <div key={s} className="flex flex-col items-center gap-[8px]">
                  <Tooltip content={`Tooltip · side="${s}"`} arrow side={s}>
                    <button className="px-[16px] py-[8px] rounded-[8px] text-[14px] font-medium text-[var(--foreground)] bg-[var(--field-bg)] border border-[var(--field-border)]">
                      {s.charAt(0).toUpperCase() + s.slice(1)}
                    </button>
                  </Tooltip>
                  <span className="text-[11px] text-[var(--field-supporting)]">side="{s}"</span>
                </div>
              ))}
            </div>
          </div>

          {/* Usage guidelines */}
          <div className="flex flex-col gap-[16px]">
            <SectionLabel>Usage guidelines</SectionLabel>
            <div className="grid grid-cols-2 gap-[16px]">
              <div className="flex flex-col gap-[10px] p-[20px] rounded-[8px]" style={{ background: "var(--ab-success-bg)" }}>
                <span className="text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--ab-success-text)" }}>Do</span>
                {[
                  "Use for brief, non-essential supplemental information triggered on hover or focus.",
                  "Keep to 1–3 lines (max 300px wide).",
                  "Use on icon-only buttons that lack a visible text label.",
                  "Position to avoid clipping at screen or container edges.",
                  "Use the arrow variant to clarify which element the tooltip refers to.",
                ].map(t => (
                  <p key={t} className="text-[13px]" style={{ color: "var(--ab-success-text)" }}>• {t}</p>
                ))}
              </div>
              <div className="flex flex-col gap-[10px] p-[20px] rounded-[8px]" style={{ background: "var(--ab-error-bg)" }}>
                <span className="text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--ab-error-text)" }}>Don't</span>
                {[
                  "Don't put critical information in a tooltip — it's invisible on mobile and to keyboard-only users who don't focus the element.",
                  "Don't include interactive elements (links, buttons) inside the tooltip.",
                  "Don't exceed 300px width.",
                  "Don't use Tooltip as the only labeling mechanism for form inputs.",
                  "Don't trigger tooltips on click — use a Popover instead.",
                ].map(t => (
                  <p key={t} className="text-[13px]" style={{ color: "var(--ab-error-text)" }}>• {t}</p>
                ))}
              </div>
            </div>
          </div>

          {/* Accessibility */}
          <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Accessibility</SectionLabel>
            {[
              "role=\"tooltip\" is applied to the tooltip container.",
              "aria-describedby is set on the wrapper element pointing to the tooltip id.",
              "Tooltip appears on keyboard focus (onFocus) and disappears on blur.",
              "Dismiss with Escape key — handled by the trigger element's default keyboard behavior.",
              "Do not place focusable or interactive elements inside the tooltip.",
              "Text/Negative (#ffffff) achieves 4.5:1+ contrast against Surface/Neutral/Darker (#111827).",
            ].map(t => (
              <p key={t} className="text-[13px] text-[var(--field-supporting)]">• {t}</p>
            ))}
          </div>

        </div>
      )}

      {/* Playground */}
      {tab === "playground" && (
        <div className="flex flex-col gap-[24px]">
          <div className="grid grid-cols-[280px_1fr] gap-[24px]">
            {/* Controls */}
            <div className="flex flex-col gap-[20px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
              <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)]">Controls</p>

              <div className="flex flex-col gap-[8px]">
                <label className="text-[12px] text-[var(--field-label)]">content</label>
                <input
                  value={pgContent}
                  onChange={e => setPgContent(e.target.value)}
                  className="px-[10px] py-[6px] rounded-[6px] text-[13px] bg-[var(--field-bg)] border border-[var(--field-border)] text-[var(--foreground)] outline-none focus:border-[var(--primary)]"
                  placeholder="Tooltip text..."
                />
              </div>

              <div className="flex flex-col gap-[8px]">
                <label className="text-[12px] text-[var(--field-label)]">side</label>
                <div className="grid grid-cols-2 gap-[6px]">
                  {(["top","right","bottom","left"] as TooltipSide[]).map(s => (
                    <button
                      key={s}
                      onClick={() => setPgSide(s)}
                      className="px-[10px] py-[6px] rounded-[6px] text-[12px] font-medium transition-colors"
                      style={{
                        background: pgSide === s ? "var(--primary)" : "var(--field-bg)",
                        color: pgSide === s ? "#ffffff" : "var(--field-supporting)",
                        border: `1px solid ${pgSide === s ? "var(--primary)" : "var(--field-border)"}`,
                      }}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex items-center justify-between">
                <label className="text-[12px] text-[var(--field-label)]">arrow</label>
                <button
                  onClick={() => setPgArrow(v => !v)}
                  className="relative w-[36px] h-[20px] rounded-full transition-colors"
                  style={{ background: pgArrow ? "var(--primary)" : "var(--toggle-track-off)", border: `1px solid ${pgArrow ? "transparent" : "var(--toggle-border-off)"}` }}
                >
                  <span
                    className="absolute top-[2px] w-[14px] h-[14px] rounded-full transition-transform"
                    style={{ background: pgArrow ? "#fff" : "var(--toggle-thumb-off)", left: pgArrow ? "19px" : "2px" }}
                  />
                </button>
              </div>
            </div>

            {/* Preview */}
            <div className="flex flex-col gap-[16px]">
              <div className="flex items-center justify-center" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)", borderRadius: 8, minHeight: 240 }}>
                <Tooltip content={pgContent || "Tooltip text"} arrow={pgArrow} side={pgSide}>
                  <button className="px-[20px] py-[10px] rounded-[8px] text-[14px] font-medium text-[var(--foreground)] bg-[var(--field-bg)] border border-[var(--field-border)] hover:border-[var(--field-border-hover)] transition-colors">
                    Hover me
                  </button>
                </Tooltip>
              </div>
              <p className="text-[12px] text-[var(--field-supporting)] text-center">Hover over the button to preview the tooltip</p>

              {/* Code snippet */}
              <div className="rounded-[8px] overflow-hidden" style={{ background: "var(--code-bg)", border: "0.5px solid var(--field-border)" }}>
                <div className="px-[16px] py-[10px]" style={{ borderBottom: "0.5px solid var(--field-border)" }}>
                  <span className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)]">Code</span>
                </div>
                <pre className="px-[16px] py-[14px] text-[12px] leading-[20px] text-[var(--foreground)] overflow-x-auto whitespace-pre-wrap">
{`import { Tooltip } from "@/components/ui/tooltip"

<Tooltip
  content="${pgContent || "Tooltip text"}"
  arrow={${pgArrow}}
  side="${pgSide}"
>
  <button>Hover me</button>
</Tooltip>`}
                </pre>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Reference */}
      {tab === "reference" && (
        <div className="flex flex-col gap-[32px]">

          <div className="flex flex-col gap-[16px]">
            <SectionLabel>When to use</SectionLabel>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--field-border)" }}>
              <table className="w-full text-[13px]">
                <thead>
                  <tr style={{ background: "var(--table-header-bg)", borderBottom: "0.5px solid var(--table-border)" }}>
                    <th className="text-left px-[16px] py-[10px] font-semibold text-[var(--table-header-text)]">Scenario</th>
                    <th className="text-left px-[16px] py-[10px] font-semibold text-[var(--table-header-text)]">Recommendation</th>
                  </tr>
                </thead>
                <tbody>
                  {[
                    ["Icon-only button or control", "Tooltip with plain variant — label the action"],
                    ["Overflow text needs full value shown", "Tooltip — show full text on hover"],
                    ["Brief contextual hint", "Tooltip plain — keep under 2 lines"],
                    ["Need to indicate arrow direction", "Tooltip with arrow=true and appropriate side"],
                    ["Critical / required information", "Do NOT use Tooltip — use inline copy or a label"],
                    ["Interactive content (links, buttons)", "Do NOT use Tooltip — use a Popover or Modal"],
                    ["Mobile or touch surfaces", "Do NOT use Tooltip — use alternative disclosure"],
                  ].map(([sc, rec], i) => (
                    <tr key={i} style={{ background: i % 2 === 0 ? "transparent" : "var(--row-alt-bg)", borderBottom: "0.5px solid var(--table-border)" }}>
                      <td className="px-[16px] py-[10px] text-[var(--foreground)]">{sc}</td>
                      <td className="px-[16px] py-[10px] text-[var(--field-supporting)]">{rec}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="flex flex-col gap-[16px]">
            <SectionLabel>Props</SectionLabel>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--field-border)" }}>
              <table className="w-full text-[13px]">
                <thead>
                  <tr style={{ background: "var(--table-header-bg)", borderBottom: "0.5px solid var(--table-border)" }}>
                    {["Prop", "Type", "Default", "Description"].map(h => (
                      <th key={h} className="text-left px-[16px] py-[10px] font-semibold text-[var(--table-header-text)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    ["content",   "string",                              "required", "Tooltip text content. Max 300px wide, 2 lines recommended."],
                    ["children",  "ReactNode",                           "required", "Trigger element — typically a button or icon."],
                    ["arrow",     "boolean",                             "false",    "Show directional arrow pointer."],
                    ["side",      '"top" | "right" | "bottom" | "left"', '"top"',    "Which side of the trigger the tooltip appears on."],
                    ["className", "string",                              "—",        "Extra classes applied to the tooltip bubble."],
                  ].map(([prop, type, def, desc], i) => (
                    <tr key={i} style={{ background: i % 2 === 0 ? "transparent" : "var(--row-alt-bg)", borderBottom: "0.5px solid var(--table-border)" }}>
                      <td className="px-[16px] py-[10px] font-mono text-[12px] text-[var(--primary)]">{prop}</td>
                      <td className="px-[16px] py-[10px] font-mono text-[12px] text-[var(--foreground)]">{type}</td>
                      <td className="px-[16px] py-[10px] font-mono text-[12px] text-[var(--field-supporting)]">{def}</td>
                      <td className="px-[16px] py-[10px] text-[var(--field-supporting)]">{desc}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="flex flex-col gap-[16px]">
            <SectionLabel>Developer Reference</SectionLabel>
            <div className="rounded-[8px] overflow-hidden" style={{ background: "var(--code-bg)", border: "0.5px solid var(--field-border)" }}>
              <div className="px-[16px] py-[10px]" style={{ borderBottom: "0.5px solid var(--field-border)" }}>
                <span className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)]">Full Code</span>
              </div>
              <pre className="px-[16px] py-[14px] text-[12px] leading-[20px] text-[var(--foreground)] overflow-x-auto">
{codeSnippet}
              </pre>
            </div>
          </div>

          <div className="flex flex-col gap-[16px]">
            <SectionLabel>Tokens</SectionLabel>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--field-border)" }}>
              <table className="w-full text-[13px]">
                <thead>
                  <tr style={{ background: "var(--table-header-bg)", borderBottom: "0.5px solid var(--table-border)" }}>
                    {["Token", "Role", "Dark", "Light"].map(h => (
                      <th key={h} className="text-left px-[16px] py-[10px] font-semibold text-[var(--table-header-text)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    ["--color-surface-neutral-darker", "Background (Surface/Neutral/Darker)", "#111827", "#111827"],
                    ["--color-text-negative",          "Text (Text/Negative)",                "#ffffff",  "#ffffff"],
                  ].map(([token, role, dark, light], i) => (
                    <tr key={i} style={{ background: i % 2 === 0 ? "transparent" : "var(--row-alt-bg)", borderBottom: "0.5px solid var(--table-border)" }}>
                      <td className="px-[16px] py-[10px] font-mono text-[12px] text-[var(--primary)]">{token}</td>
                      <td className="px-[16px] py-[10px] text-[var(--field-supporting)]">{role}</td>
                      <td className="px-[16px] py-[10px]">
                        <span className="flex items-center gap-[8px]">
                          <span className="w-[14px] h-[14px] rounded-[3px] inline-block border border-[var(--field-border)]" style={{ background: dark }} />
                          <span className="font-mono text-[12px] text-[var(--foreground)]">{dark}</span>
                        </span>
                      </td>
                      <td className="px-[16px] py-[10px]">
                        <span className="flex items-center gap-[8px]">
                          <span className="w-[14px] h-[14px] rounded-[3px] inline-block border border-[var(--field-border)]" style={{ background: light }} />
                          <span className="font-mono text-[12px] text-[var(--foreground)]">{light}</span>
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

        </div>
      )}

    </div>
  )
}

// ── ScrollAreaPage ────────────────────────────────────────────────────────────

function ScrollAreaPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab,    setTab]    = useState<"overview" | "playground" | "reference">("overview")
  const [pgAxis, setPgAxis] = useState<"y" | "x" | "both">("y")

  const DEMO_ROWS = Array.from({ length: 18 }, (_, i) => ({
    id:   i,
    w1:   [72, 55, 80, 64, 70, 58, 78, 62][i % 8],
    w2:   [45, 60, 38, 55, 42, 65, 50, 48][i % 8],
    w3:   [30, 40, 25, 35, 28, 38, 32, 36][i % 8],
  }))

  const DEMO_COLS = Array.from({ length: 14 }, (_, i) => 80 + (i % 3) * 20)

  const codeSnippet = `import { ScrollArea } from "@/components/ui/scroll-area"

// Vertical scroll (default) — 8px padding-right keeps content away from thumb
<ScrollArea className="h-[320px] pr-[8px]">
  {/* overflowing content */}
</ScrollArea>

// Horizontal scroll
<ScrollArea axis="x" className="pb-[8px]">
  <div className="flex gap-[8px] w-max">
    {/* wide content */}
  </div>
</ScrollArea>

// Both axes
<ScrollArea axis="both" className="h-[320px] pr-[8px] pb-[8px]">
  {/* 2D overflow content */}
</ScrollArea>`

  return (
    <div>
      {/* Header */}
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Scroll Area</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px] max-w-[560px]">
            Scrollable container with a DS-branded 4px custom scrollbar. The thumb is hidden by default and appears on hover.
            Supports vertical, horizontal, or both axes. Always maintain 8px (Spacing/2x) between the scrollbar and content.
          </p>
        </div>
        <SpecButton onClick={() => openSpec("scroll-area")} />
      </div>

      {/* Page nav */}
      <div className="flex gap-[4px] mb-[32px] border-b border-[var(--table-border)]">
        {(["overview", "playground", "reference"] as const).map(t => (
          <button key={t} onClick={() => setTab(t)}
            className="px-[14px] py-[8px] text-[13px] font-semibold capitalize transition-colors"
            style={{ color: tab === t ? "var(--primary)" : "var(--field-supporting)", borderBottom: tab === t ? "2px solid var(--primary)" : "2px solid transparent", marginBottom: -1 }}
          >
            {t.charAt(0).toUpperCase() + t.slice(1)}
          </button>
        ))}
      </div>

      {/* ── Overview ─────────────────────────────────────────────────────── */}
      {tab === "overview" && (
        <div className="flex flex-col gap-[40px]">

          {/* Vertical */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[8px]">Vertical scroll</p>
            <p className="text-[12px] mb-[12px]" style={{ color: "var(--field-supporting)" }}>
              Default axis. Set a fixed height and add <code className="font-mono text-[11px] px-[4px] py-[0.5px] rounded-[3px]" style={{ background: "var(--surface-raised)" }}>pr-[8px]</code> to keep content 8px from the thumb.
            </p>
            <ScrollArea className="h-[220px] pr-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)", borderRadius: 8 }}>
              <div className="p-[16px] flex flex-col gap-[8px]">
                {DEMO_ROWS.map(row => (
                  <div key={row.id} className="flex items-center gap-[10px]">
                    <div className="h-[8px] rounded-[4px] flex-shrink-0" style={{ background: "var(--surface-raised)", width: `${row.w1}%` }} />
                    <div className="h-[8px] rounded-[4px] flex-shrink-0" style={{ background: "var(--surface-raised)", width: `${row.w2}%` }} />
                  </div>
                ))}
              </div>
            </ScrollArea>
          </section>

          {/* Horizontal */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[8px]">Horizontal scroll</p>
            <p className="text-[12px] mb-[12px]" style={{ color: "var(--field-supporting)" }}>
              Use <code className="font-mono text-[11px] px-[4px] py-[0.5px] rounded-[3px]" style={{ background: "var(--surface-raised)" }}>axis="x"</code> with <code className="font-mono text-[11px] px-[4px] py-[0.5px] rounded-[3px]" style={{ background: "var(--surface-raised)" }}>pb-[8px]</code> to keep content 8px above the thumb.
            </p>
            <ScrollArea axis="x" className="pb-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)", borderRadius: 8 }}>
              <div className="p-[16px] flex gap-[8px]" style={{ width: "max-content" }}>
                {DEMO_COLS.map((w, i) => (
                  <div key={i} className="h-[72px] rounded-[6px] flex-shrink-0" style={{ background: "var(--surface-raised)", width: w }} />
                ))}
              </div>
            </ScrollArea>
          </section>

          {/* Usage guidelines */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Usage guidelines</p>
            <div className="grid grid-cols-2 gap-[12px]">
              <div className="rounded-[8px] p-[16px] flex flex-col gap-[12px]" style={{ background: "var(--surface-raised)", border: "0.5px solid var(--field-border)" }}>
                <span className="text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--color-surface-success-default)" }}>✓ Do</span>
                <ul className="flex flex-col gap-[8px]">
                  {[
                    "Use when a container has overflow content beyond its defined boundaries.",
                    "Apply pr-[8px] (vertical) or pb-[8px] (horizontal) to maintain the 8px Spacing/2x gap.",
                    "Use only Size S (4px) — the only supported size.",
                    "Support vertical and horizontal overflow scenarios.",
                    "Let the scrollbar appear naturally on hover — never force it to show persistently.",
                  ].map((t, i) => (
                    <li key={i} className="text-[12px]" style={{ color: "var(--foreground)" }}>{t}</li>
                  ))}
                </ul>
              </div>
              <div className="rounded-[8px] p-[16px] flex flex-col gap-[12px]" style={{ background: "var(--surface-raised)", border: "0.5px solid var(--field-border)" }}>
                <span className="text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--color-surface-error-default)" }}>✕ Don't</span>
                <ul className="flex flex-col gap-[8px]">
                  {[
                    "Don't show the scrollbar permanently — thumb must appear only on hover/scroll.",
                    "Don't use custom widths or override the 4px default.",
                    "Don't skip the 8px gap between the thumb and the scrollable content.",
                    "Don't use inside non-scrollable containers.",
                    "Don't use M size — it has been deprecated; only S (4px) is supported.",
                  ].map((t, i) => (
                    <li key={i} className="text-[12px]" style={{ color: "var(--foreground)" }}>{t}</li>
                  ))}
                </ul>
              </div>
            </div>
          </section>

          {/* Code snippet */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Code snippet</p>
            <pre className="rounded-[8px] p-[16px] text-[12px] font-mono leading-[1.7] overflow-x-auto" style={{ background: "var(--code-bg)", border: "0.5px solid var(--field-border)", color: "var(--field-text)" }}>{codeSnippet}</pre>
          </section>
        </div>
      )}

      {/* ── Playground ───────────────────────────────────────────────────── */}
      {tab === "playground" && (
        <div className="flex flex-col gap-[24px]">
          {/* Controls */}
          <div className="flex flex-wrap gap-[24px] p-[20px] rounded-[8px]" style={{ background: "var(--surface-raised)", border: "0.5px solid var(--field-border)" }}>
            <div className="flex flex-col gap-[6px]">
              <span className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)]">Axis</span>
              <div className="flex gap-[6px]">
                {(["y", "x", "both"] as const).map(v => (
                  <button key={v} onClick={() => setPgAxis(v)}
                    className="px-[12px] py-[6px] rounded-[6px] text-[12px] font-medium transition-colors"
                    style={{ background: pgAxis === v ? "var(--primary)" : "var(--surface)", color: pgAxis === v ? "#fff" : "var(--foreground)", border: "0.5px solid var(--field-border)" }}
                  >{v}</button>
                ))}
              </div>
            </div>
          </div>

          {/* Demo */}
          <ScrollArea
            axis={pgAxis}
            className={pgAxis === "y" ? "h-[300px] pr-[8px]" : pgAxis === "x" ? "pb-[8px]" : "h-[300px] pr-[8px] pb-[8px]"}
            style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)", borderRadius: 8 }}
          >
            {pgAxis === "x" ? (
              <div className="p-[16px] flex gap-[8px]" style={{ width: "max-content" }}>
                {DEMO_COLS.map((w, i) => (
                  <div key={i} className="h-[80px] rounded-[6px] flex-shrink-0" style={{ background: "var(--surface-raised)", width: w }} />
                ))}
              </div>
            ) : (
              <div className="p-[16px] flex flex-col gap-[8px]">
                {DEMO_ROWS.map(row => (
                  <div key={row.id} className="flex items-center gap-[10px]">
                    <div className="h-[8px] rounded-[4px]" style={{ background: "var(--surface-raised)", width: `${row.w1}%` }} />
                    <div className="h-[8px] rounded-[4px]" style={{ background: "var(--surface-raised)", width: `${row.w2}%` }} />
                  </div>
                ))}
                {pgAxis === "both" && (
                  <div className="flex gap-[8px] mt-[8px]" style={{ width: "max-content" }}>
                    {DEMO_COLS.slice(0, 8).map((w, i) => (
                      <div key={i} className="h-[40px] rounded-[6px] flex-shrink-0" style={{ background: "var(--primary)", opacity: 0.15, width: w }} />
                    ))}
                  </div>
                )}
              </div>
            )}
          </ScrollArea>
        </div>
      )}

      {/* ── Reference ────────────────────────────────────────────────────── */}
      {tab === "reference" && (
        <div className="flex flex-col gap-[40px]">

          {/* Props */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">ScrollAreaProps</p>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--field-border)" }}>
              <table className="w-full text-[12px]">
                <thead>
                  <tr style={{ background: "var(--surface-raised)", borderBottom: "0.5px solid var(--field-border)" }}>
                    {["Prop", "Type", "Default", "Description"].map(h => (
                      <th key={h} className="px-[12px] py-[8px] text-left font-semibold text-[var(--field-supporting)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    { prop: "children",  type: "ReactNode",             def: "required", desc: "Content to scroll." },
                    { prop: "axis",      type: '"y" | "x" | "both"',    def: '"y"',      desc: 'Scroll axis. "y" = vertical, "x" = horizontal, "both" = 2D.' },
                    { prop: "className", type: "string",                 def: "—",        desc: "Extra Tailwind classes. Add h-[N] for vertical, w-[N] for horizontal." },
                    { prop: "style",     type: "React.CSSProperties",    def: "—",        desc: "Inline styles passed to the container div." },
                  ].map((r, i) => (
                    <tr key={i} style={{ borderBottom: "0.5px solid var(--field-border)", background: i % 2 === 0 ? "transparent" : "var(--surface-raised)" }}>
                      <td className="px-[12px] py-[8px] font-mono" style={{ color: "var(--primary)" }}>{r.prop}</td>
                      <td className="px-[12px] py-[8px] font-mono" style={{ color: "var(--field-supporting)" }}>{r.type}</td>
                      <td className="px-[12px] py-[8px] font-mono" style={{ color: "var(--field-supporting)" }}>{r.def}</td>
                      <td className="px-[12px] py-[8px]" style={{ color: "var(--foreground)" }}>{r.desc}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>

          {/* Tokens */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Design tokens</p>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--field-border)" }}>
              <table className="w-full text-[12px]">
                <thead>
                  <tr style={{ background: "var(--surface-raised)", borderBottom: "0.5px solid var(--field-border)" }}>
                    {["Token", "Figma source", "Usage"].map(h => (
                      <th key={h} className="px-[12px] py-[8px] text-left font-semibold text-[var(--field-supporting)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    { token: "--field-scrollbar-thumb", src: "Surface/Neutral/Emphasis",  usage: "Thumb color (default state)" },
                    { token: "--scrollbar-thumb-hover", src: "Surface/Neutral/Focus",     usage: "Thumb color on thumb hover" },
                  ].map((r, i) => (
                    <tr key={i} style={{ borderBottom: "0.5px solid var(--field-border)", background: i % 2 === 0 ? "transparent" : "var(--surface-raised)" }}>
                      <td className="px-[12px] py-[8px] font-mono" style={{ color: "var(--primary)" }}>{r.token}</td>
                      <td className="px-[12px] py-[8px] font-mono" style={{ color: "var(--field-supporting)" }}>{r.src}</td>
                      <td className="px-[12px] py-[8px]" style={{ color: "var(--foreground)" }}>{r.usage}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>

          {/* Specs */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Specs</p>
            <div className="flex flex-col gap-[8px]">
              {[
                ["Size",      "S only — 4px width/height. M size is deprecated."],
                ["Gap",       "Always 8px (Spacing/2x) between thumb and scrollable content. Apply pr-[8px] (vertical) or pb-[8px] (horizontal) to the ScrollArea."],
                ["Behavior",  "Thumb is hidden until the user hovers the container. Appears automatically on macOS overlay scrollbars when scrolling begins."],
                ["CSS class", "Applies .aims-scroll — do not override width or background on the scrollbar pseudo-elements."],
              ].map(([label, desc], i) => (
                <div key={i} className="flex gap-[12px] py-[10px] px-[12px] rounded-[6px]" style={{ background: "var(--surface-raised)", border: "0.5px solid var(--field-border)" }}>
                  <span className="text-[12px] font-semibold flex-shrink-0 w-[80px]" style={{ color: "var(--field-supporting)" }}>{label}</span>
                  <span className="text-[12px]" style={{ color: "var(--foreground)" }}>{desc}</span>
                </div>
              ))}
            </div>
          </section>
        </div>
      )}
    </div>
  )
}

// ── Pattern page helpers ─────────────────────────────────────────────────────

function PatternTabRow({ tab, setTab }: { tab: string; setTab: (t: string) => void }) {
  return (
    <div className="flex gap-[4px] mb-[32px] border-b border-[var(--table-border)]">
      {(["when-to-use", "anatomy", "rules"] as const).map(t => (
        <button key={t} onClick={() => setTab(t)}
          className="px-[14px] py-[8px] text-[13px] font-semibold capitalize transition-colors"
          style={{ color: tab === t ? "var(--primary)" : "var(--field-supporting)", borderBottom: tab === t ? "2px solid var(--primary)" : "2px solid transparent", marginBottom: -1 }}>
          {t === "when-to-use" ? "When to Use" : t === "anatomy" ? "Anatomy" : "Rules"}
        </button>
      ))}
    </div>
  )
}

function PatternCard({ children }: { children: React.ReactNode }) {
  return (
    <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
      {children}
    </div>
  )
}

function WireBlock({ label, h, flex, bg }: { label: string; h?: number | string; flex?: number; bg?: string }) {
  return (
    <div className="flex items-center justify-center rounded-[4px] shrink-0"
      style={{ height: h ?? 40, flex: flex ?? "none", background: bg ?? "var(--color-surface-neutral-default)", border: "1px dashed var(--field-border)", minWidth: 40, fontSize: 11, fontWeight: 600, color: "var(--field-label)", letterSpacing: "0.04em", textTransform: "uppercase", padding: "4px 8px", textAlign: "center" }}>
      {label}
    </div>
  )
}

function PatternRules({ code }: { code: string }) {
  return (
    <pre className="text-[11px] leading-[18px] overflow-x-auto p-[16px] rounded-[6px] whitespace-pre-wrap"
      style={{ background: "var(--canvas)", color: "var(--foreground)", fontFamily: "monospace" }}>
      {code}
    </pre>
  )
}

function DecisionRow({ condition, result, component }: { condition: string; result: string; component: string }) {
  return (
    <tr style={{ borderBottom: "0.5px solid var(--table-border)" }}>
      <td className="px-[12px] py-[10px] text-[13px] text-[var(--foreground)]">{condition}</td>
      <td className="px-[12px] py-[10px] text-[13px] font-semibold" style={{ color: "var(--primary)" }}>{result}</td>
      <td className="px-[12px] py-[10px]">
        <span className="text-[11px] font-mono px-[6px] py-[2px] rounded-[3px]" style={{ background: "var(--color-surface-primary-subtle)", color: "var(--primary)" }}>{component}</span>
      </td>
    </tr>
  )
}

