type WidgetId = "kpi" | "timeline" | "charts" | "table" | "activity" | "notes" | "folder-nav" | "progress-comparison" | "status-warning"

interface WidgetDef {
  id: WidgetId
  name: string
  classNum: 1 | 2 | 3
  classLabel: "Compact" | "Standard" | "Heavy"
  widthOptions: string[]
  heightGU: string
  defined: boolean
  description: string
  states: string[]
  contentVariants?: string[]
  useCases: string[]
  dontUse: string[]
  figmaNodeId?: string
}

