const DEMO_ITEMS_2 = [
  { id: "list",     label: "List"     },
  { id: "grid",     label: "Grid"     },
]
const DEMO_ITEMS_3 = [
  { id: "all",      label: "All"      },
  { id: "active",   label: "Active"   },
  { id: "archived", label: "Archived" },
]
const DEMO_ITEMS_4 = [
  { id: "overview",  label: "Overview"  },
  { id: "details",   label: "Details"   },
  { id: "activity",  label: "Activity"  },
  { id: "settings",  label: "Settings"  },
]
const DEMO_ITEMS_5 = [
  { id: "overview",  label: "Overview"  },
  { id: "details",   label: "Details"   },
  { id: "activity",  label: "Activity"  },
  { id: "settings",  label: "Settings"  },
  { id: "insights",  label: "Insights"  },
]
const DEMO_ITEMS_6 = [
  { id: "overview",  label: "Overview"  },
  { id: "details",   label: "Details"   },
  { id: "activity",  label: "Activity"  },
  { id: "settings",  label: "Settings"  },
  { id: "insights",  label: "Insights"  },
  { id: "history",   label: "History"   },
]

function SwitchTabPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab, setTab]             = useState<"overview" | "playground" | "reference">("overview")
  const [pgSize, setPgSize]       = useState<SwitchTabSize>("m")
  const [pgCount, setPgCount]     = useState<"2" | "3" | "4" | "5" | "6">("3")
  const [pgActive, setPgActive]   = useState("all")

  const pgItems =
    pgCount === "2" ? DEMO_ITEMS_2 :
    pgCount === "3" ? DEMO_ITEMS_3 :
    pgCount === "4" ? DEMO_ITEMS_4 :
    pgCount === "5" ? DEMO_ITEMS_5 :
    DEMO_ITEMS_6
  const pgValue = pgItems.find(i => i.id === pgActive) ? pgActive : pgItems[0].id

  return (
    <div>
      {/* Header */}
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Switch Tab</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px] max-w-[620px]">
            Segmented tab switcher for top-level navigation within a contained view or panel. White pill-shaped container with 2–7 equal-width tab items, blue active fill, and full keyboard navigation.
          </p>
        </div>
        <SpecButton onClick={() => openSpec("switch-tab")} />
      </div>

      {/* Tab row */}
      <div className="flex gap-[4px] mb-[32px] border-b border-[var(--table-border)]">
        {(["overview", "playground", "reference"] as const).map(t => (
          <button key={t} onClick={() => setTab(t)}
            className="px-[14px] py-[8px] text-[13px] font-semibold capitalize transition-colors"
            style={{ color: tab === t ? "var(--primary)" : "var(--field-supporting)", borderBottom: tab === t ? "2px solid var(--primary)" : "2px solid transparent", marginBottom: -1 }}>
            {t.charAt(0).toUpperCase() + t.slice(1)}
          </button>
        ))}
      </div>

      {/* ── Overview ── */}
      {tab === "overview" && (
        <div className="flex flex-col gap-[32px]">

          {/* Anatomy */}
          <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Anatomy</SectionLabel>
            <div className="overflow-x-auto">
              <table className="w-full text-[13px]" style={{ borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ borderBottom: "1px solid var(--table-border)" }}>
                    {["#", "Element", "Description"].map(h => (
                      <th key={h} className="px-[12px] py-[8px] text-left font-semibold text-[var(--field-label)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    ["1", "Container",           "White pill-shaped wrapper (Elevation-5 shadow) that holds all tab items."],
                    ["2", "Tab Item — Inactive", "Transparent background · neutral text · receives focus via keyboard (← →)."],
                    ["3", "Tab Item — Active",   "Blue tinted fill (Surface/Primary/More Subtle) · blue SemiBold label (Text/Link)."],
                    ["4", "Tab Label",           "Text identifying each option. Keep to 1–3 words max."],
                    ["5", "Optional Icon",       "16px icon rendered before the label inside the tab item. Same color as label."],
                  ].map(([n, el, desc]) => (
                    <tr key={n} style={{ borderBottom: "0.5px solid var(--table-border)" }}>
                      <td className="px-[12px] py-[8px] text-[var(--field-supporting)]">{n}</td>
                      <td className="px-[12px] py-[8px] font-medium text-[var(--foreground)]">{el}</td>
                      <td className="px-[12px] py-[8px] text-[var(--field-supporting)]">{desc}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Sizes */}
          <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Sizes</SectionLabel>
            <div className="flex flex-col gap-[20px]">
              {([
                { size: "m" as SwitchTabSize, label: "M — 48px",  desc: "px-12 / py-4 · 16px font · default" },
                { size: "s" as SwitchTabSize, label: "S — 44px",  desc: "px-8 / py-4 · 14px font · compact contexts" },
              ] as const).map(({ size, label, desc }) => (
                <div key={size} className="flex flex-col gap-[8px]">
                  <div className="flex items-center gap-[8px]">
                    <span className="text-[12px] font-semibold text-[var(--field-label)] uppercase tracking-wide w-[80px]">{label}</span>
                    <span className="text-[12px] text-[var(--field-supporting)]">{desc}</span>
                  </div>
                  <SwitchTab items={DEMO_ITEMS_3} defaultValue="all" size={size} />
                </div>
              ))}
            </div>
          </div>

          {/* Quantity variants */}
          <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Quantity Variants (2–6 shown)</SectionLabel>
            <div className="flex flex-col gap-[16px]">
              {[
                { items: DEMO_ITEMS_2, label: "2 items" },
                { items: DEMO_ITEMS_3, label: "3 items" },
                { items: DEMO_ITEMS_4, label: "4 items" },
                { items: DEMO_ITEMS_5, label: "5 items" },
                { items: DEMO_ITEMS_6, label: "6 items" },
              ].map(({ items, label }) => (
                <div key={label} className="flex items-center gap-[16px]">
                  <span className="text-[12px] text-[var(--field-supporting)] w-[56px] shrink-0">{label}</span>
                  <SwitchTab items={items} defaultValue={items[0].id} />
                </div>
              ))}
            </div>
          </div>

          {/* Do / Don't */}
          <div className="grid grid-cols-2 gap-[12px]">
            <div className="p-[20px] rounded-[8px] flex flex-col gap-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--tag-success-bd)" }}>
              <p className="text-[13px] font-semibold" style={{ color: "var(--tag-success-fg)" }}>✅ Do</p>
              {[
                "Use for top-level navigation switching within a contained view or panel.",
                "Keep tab labels short and scannable (1–3 words maximum).",
                "Always keep exactly one tab active at a time.",
                "Choose the tab count that matches the number of options (2–7).",
              ].map(d => <p key={d} className="text-[13px] text-[var(--field-supporting)]">· {d}</p>)}
            </div>
            <div className="p-[20px] rounded-[8px] flex flex-col gap-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--tag-error-bd)" }}>
              <p className="text-[13px] font-semibold" style={{ color: "var(--tag-error-fg)" }}>❌ Don't</p>
              {[
                "Don't use as a multi-select or form toggle — only one tab can be active.",
                "Don't add more than 7 tabs; use a dropdown or menu for larger sets.",
                "Don't use when tab content requires deep navigation or separate pages.",
                "Don't mix icon-only and text tabs within the same switcher.",
              ].map(d => <p key={d} className="text-[13px] text-[var(--field-supporting)]">· {d}</p>)}
            </div>
          </div>

        </div>
      )}

      {/* ── Playground ── */}
      {tab === "playground" && (
        <div className="flex flex-col gap-[28px]">
          {/* Controls */}
          <div className="flex flex-col gap-[20px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Controls</SectionLabel>
            <CtrlGroup<SwitchTabSize> label="Size" value={pgSize} onChange={v => { setPgSize(v); setPgActive("") }}
              options={[
                { value: "m", label: "M — 48px" },
                { value: "s", label: "S — 44px" },
              ]} />
            <CtrlGroup<"2" | "3" | "4" | "5" | "6"> label="Item count" value={pgCount} onChange={v => { setPgCount(v); setPgActive("") }}
              options={[
                { value: "2", label: "2 items" },
                { value: "3", label: "3 items" },
                { value: "4", label: "4 items" },
                { value: "5", label: "5 items" },
                { value: "6", label: "6 items" },
              ]} />
          </div>
          {/* Preview */}
          <div className="flex flex-col gap-[12px] p-[24px] rounded-[8px] items-center" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Preview</SectionLabel>
            <SwitchTab items={pgItems} value={pgValue} onChange={setPgActive} size={pgSize} aria-label="Demo navigation" />
            <p className="text-[12px] text-[var(--field-supporting)] mt-[8px]">Active: <code className="font-mono text-[var(--primary)]">{pgValue}</code></p>
          </div>
        </div>
      )}

      {/* ── Reference ── */}
      {tab === "reference" && (
        <div className="flex flex-col gap-[28px]">
          {/* Token table */}
          <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Design Tokens</SectionLabel>
            <div className="overflow-x-auto">
              <table className="w-full text-[13px]" style={{ borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ borderBottom: "1px solid var(--table-border)" }}>
                    {["Token", "DS Token", "Light", "Dark"].map(h => (
                      <th key={h} className="px-[12px] py-[8px] text-left font-semibold text-[var(--field-label)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {SWITCH_TAB_SPEC.variants.flatMap(v => v.tokens).map((row, i) => (
                    <tr key={i} style={{ borderBottom: "0.5px solid var(--table-border)" }}>
                      <td className="px-[12px] py-[8px] font-medium text-[var(--foreground)]">{row.role}</td>
                      <td className="px-[12px] py-[8px] font-mono text-[11px]" style={{ color: "var(--primary)" }}>{row.variable}</td>
                      <td className="px-[12px] py-[8px] font-mono text-[11px] text-[var(--field-supporting)]">{row.light}</td>
                      <td className="px-[12px] py-[8px] font-mono text-[11px] text-[var(--field-supporting)]">{row.dark}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Props table */}
          <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>Props</SectionLabel>
            <div className="overflow-x-auto">
              <table className="w-full text-[13px]" style={{ borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ borderBottom: "1px solid var(--table-border)" }}>
                    {["Prop", "Type", "Default", "Description"].map(h => (
                      <th key={h} className="px-[12px] py-[8px] text-left font-semibold text-[var(--field-label)]">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {(SWITCH_TAB_SPEC.properties as { name: string; type: string; default: string; note: string }[]).map((row, i) => (
                    <tr key={i} style={{ borderBottom: "0.5px solid var(--table-border)" }}>
                      <td className="px-[12px] py-[8px] font-mono text-[12px]" style={{ color: "var(--primary)" }}>{row.name}</td>
                      <td className="px-[12px] py-[8px] font-mono text-[12px] text-[var(--field-supporting)]">{row.type}</td>
                      <td className="px-[12px] py-[8px] font-mono text-[12px] text-[var(--field-supporting)]">{row.default}</td>
                      <td className="px-[12px] py-[8px] text-[var(--field-supporting)]">{row.note}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Code snippet */}
          <div className="flex flex-col gap-[12px] p-[20px] rounded-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>JSX Usage</SectionLabel>
            <pre className="text-[12px] leading-[20px] p-[16px] rounded-[6px] overflow-x-auto" style={{ background: "var(--surface-raised)", color: "var(--field-label)" }}>{`import { SwitchTab } from "@/components/ui/switch-tab"

// Uncontrolled
<SwitchTab
  items={[
    { id: "all",      label: "All"      },
    { id: "active",   label: "Active"   },
    { id: "archived", label: "Archived" },
  ]}
  defaultValue="all"
  size="m"
/>

// Controlled
const [view, setView] = useState("all")
<SwitchTab
  items={items}
  value={view}
  onChange={setView}
  size="s"
  aria-label="Filter by status"
/>`}</pre>
          </div>

          {/* Accessibility */}
          <div className="p-[20px] rounded-[8px] flex flex-col gap-[8px]" style={{ background: "var(--surface)", border: "0.5px solid var(--field-border)" }}>
            <SectionLabel>♿ Accessibility</SectionLabel>
            {[
              "role=\"tablist\" on the container; role=\"tab\" on each button.",
              "aria-selected=\"true\" on the active tab; false on all others.",
              "tabIndex={0} on active tab only — others use -1 (roving tabindex).",
              "← → arrows navigate between tabs; Enter / Space activate the focused tab.",
              "aria-controls links each tab to its corresponding panel via the tab id.",
              "Focus indicator: 2px ring in var(--primary) with 1px offset.",
            ].map(d => <p key={d} className="text-[13px] text-[var(--field-supporting)]">· {d}</p>)}
          </div>
        </div>
      )}
    </div>
  )
}

// ── TabsPage ─────────────────────────────────────────────────────────────────

function TabsPage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab, setTab]           = useState<"overview" | "playground" | "reference">("overview")
  const [pgActive,  setPgActive]  = useState("overview")
  const [pgSize,    setPgSize]    = useState<"m" | "s">("m")
  const [pgIcon,    setPgIcon]    = useState(true)
  const [pgDisabled,setPgDisabled]= useState(false)

  const ICONS_FOR_DEMO = [
    LucideIcons.User     as LucideIcon,
    LucideIcons.Clock    as LucideIcon,
    LucideIcons.FileText as LucideIcon,
    LucideIcons.Settings as LucideIcon,
  ]
  const BASE_LABELS = ["Overview", "Activity", "Notes", "Settings"]
  const BASE_IDS    = ["overview", "activity", "notes", "settings"]

  const pgItems: TabItem[] = BASE_IDS.map((id, i) => ({
    id,
    label:    BASE_LABELS[i],
    icon:     pgIcon ? ICONS_FOR_DEMO[i] : undefined,
    disabled: pgDisabled && id === "settings",
  }))

  const Tog = ({ label, val, set }: { label: string; val: boolean; set: (v: boolean) => void }) => (
    <label className="flex items-center gap-[8px] cursor-pointer select-none">
      <div onClick={() => set(!val)} className="relative w-[32px] h-[18px] rounded-full transition-colors cursor-pointer flex-shrink-0" style={{ background: val ? "var(--primary)" : "var(--ctrl-inactive-bg)" }}>
        <div className="absolute top-[2px] w-[14px] h-[14px] rounded-full transition-all" style={{ background: "#ffffff", left: val ? "16px" : "2px" }} />
      </div>
      <span className="text-[12px] font-medium" style={{ color: "var(--foreground)" }}>{label}</span>
    </label>
  )

  const codeSnippet = `import { Tabs, type TabItem } from "@/components/ui/tabs"
import { User, Clock, FileText, Settings } from "lucide-react"
import { useState } from "react"

const items: TabItem[] = [
  { id: "overview", label: "Overview", icon: User },
  { id: "activity", label: "Activity", icon: Clock },
  { id: "notes",    label: "Notes",    icon: FileText },
  { id: "settings", label: "Settings", icon: Settings, disabled: true },
]

// Primary pattern — standalone at page / detail view / slide-out / modal level
export function TabBar() {
  const [active, setActive] = useState("overview")
  return (
    <Tabs items={items} activeId={active} onChange={setActive} />
  )
}`

  return (
    <div>
      {/* Header */}
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Tabs</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px] max-w-[560px]">
            Horizontal navigation bar for switching between related views within the same context.
            Active tab shows a primary-blue bottom indicator and label. Supports icons and disabled tabs.
          </p>
        </div>
        <SpecButton onClick={() => openSpec("tabs")} />
      </div>

      {/* Page nav */}
      <div className="flex gap-[4px] mb-[32px] border-b border-[var(--table-border)]">
        {(["overview", "playground", "reference"] as const).map(t => (
          <button key={t} onClick={() => setTab(t)}
            className="px-[14px] py-[8px] text-[13px] font-semibold capitalize transition-colors"
            style={{ color: tab === t ? "var(--primary)" : "var(--field-supporting)", borderBottom: tab === t ? "2px solid var(--primary)" : "2px solid transparent", marginBottom: -1 }}
          >
            {t.charAt(0).toUpperCase() + t.slice(1)}
          </button>
        ))}
      </div>

      {/* ── Overview ──────────────────────────────────────────────────── */}
      {tab === "overview" && (
        <div className="flex flex-col gap-[40px]">

          {/* Preview — primary pattern */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[8px]">Standalone</p>
            <p className="text-[12px] mb-[12px]" style={{ color: "var(--field-supporting)" }}>
              Tabs sit directly on any surface — no wrapper needed. Place at the top of a detail view, slide-out, modal body, or section.
            </p>
            <Tabs
              activeId="overview" onChange={() => {}}
              items={BASE_IDS.map((id, i) => ({ id, label: BASE_LABELS[i], icon: ICONS_FOR_DEMO[i] }))}
            />
            <div className="mt-[20px] flex flex-col gap-[8px]">
              {[80, 60, 72].map((w, i) => (
                <div key={i} className="h-[11px] rounded-[4px]" style={{ background: "var(--surface-raised)", width: `${w}%` }} />
              ))}
            </div>
          </section>

          {/* Sizes */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Sizes</p>
            <div className="flex flex-col gap-[16px]">
              <div>
                <p className="text-[11px] text-[var(--field-supporting)] mb-[8px]">Size M — default · 14px · px-16 py-10</p>
                <Tabs size="m" activeId="overview" onChange={() => {}}
                  items={BASE_IDS.map((id, i) => ({ id, label: BASE_LABELS[i], icon: ICONS_FOR_DEMO[i] }))}
                />
              </div>
              <div>
                <p className="text-[11px] text-[var(--field-supporting)] mb-[8px]">Size S — compact · 12px · px-12 py-8</p>
                <Tabs size="s" activeId="overview" onChange={() => {}}
                  items={BASE_IDS.map((id, i) => ({ id, label: BASE_LABELS[i], icon: ICONS_FOR_DEMO[i] }))}
                />
              </div>
            </div>
          </section>

          {/* Label only */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Label only</p>
            <Tabs activeId="all" onChange={() => {}}
              items={[
                { id: "all",       label: "All Cases" },
                { id: "open",      label: "Open"      },
                { id: "in-review", label: "In Review" },
                { id: "closed",    label: "Closed"    },
              ]}
            />
          </section>

          {/* Disabled */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">With disabled tab</p>
            <Tabs activeId="overview" onChange={() => {}}
              items={BASE_IDS.map((id, i) => ({ id, label: BASE_LABELS[i], icon: ICONS_FOR_DEMO[i], disabled: id === "settings" }))}
            />
          </section>

          {/* Usage guidelines */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Usage guidelines</p>
            <div className="grid grid-cols-2 gap-[12px]">
              <div className="rounded-[8px] p-[16px] flex flex-col gap-[12px]" style={{ background: "var(--surface-raised)", border: "0.5px solid var(--field-border)" }}>
                <span className="text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--color-surface-success-default)" }}>✓ Do</span>
                <ul className="flex flex-col gap-[8px]">
                  {[
                    "Switch between related views within the same context.",
                    "Keep tab labels concise — 1 to 3 words.",
                    "Maintain exactly one active tab at all times.",
                    "Use icons to reinforce meaning visually when helpful.",
                    "Use size S in compact layouts or nested panels.",
                  ].map((t, i) => (
                    <li key={i} className="text-[12px]" style={{ color: "var(--foreground)" }}>{t}</li>
                  ))}
                </ul>
              </div>
              <div className="rounded-[8px] p-[16px] flex flex-col gap-[12px]" style={{ background: "var(--surface-raised)", border: "0.5px solid var(--field-border)" }}>
                <span className="text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--color-surface-error-default)" }}>✕ Don't</span>
                <ul className="flex flex-col gap-[8px]">
                  {[
                    "Use for sequential steps — use a Stepper instead.",
                    "Use for navigation between pages — use Sidebar or Topbar.",
                    "Exceed 5 tabs — the bar won't fit most containers.",
                    "Mix icon and no-icon tabs in the same bar.",
                    "Disable all tabs simultaneously.",
                  ].map((t, i) => (
                    <li key={i} className="text-[12px]" style={{ color: "var(--foreground)" }}>{t}</li>
                  ))}
                </ul>
              </div>
            </div>
          </section>

          {/* Code snippet */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Code snippet</p>
            <pre className="rounded-[8px] p-[16px] text-[12px] font-mono overflow-x-auto leading-[1.6]"
              style={{ background: "var(--surface-raised)", color: "var(--foreground)", border: "0.5px solid var(--field-border)" }}>
              <code>{codeSnippet}</code>
            </pre>
          </section>
        </div>
      )}

      {/* ── Playground ──────────────────────────────────────────────── */}
      {tab === "playground" && (
        <div className="flex flex-col gap-[24px]">
          {/* Demo — standalone, no wrapper */}
          <Tabs items={pgItems} activeId={pgActive} onChange={setPgActive} size={pgSize} />

          <CardContainer size="sm">
            <div className="flex flex-col gap-[20px]">
              {/* Size */}
              <div>
                <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[10px]">Size</p>
                <div className="flex gap-[8px]">
                  {(["m", "s"] as const).map(s => (
                    <button key={s} onClick={() => setPgSize(s)}
                      className="px-[14px] py-[6px] rounded-[6px] text-[12px] font-semibold transition-colors"
                      style={{ background: pgSize === s ? "var(--primary)" : "var(--ctrl-inactive-bg)", color: pgSize === s ? "#ffffff" : "var(--field-supporting)" }}
                    >
                      {s.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>

              {/* Options */}
              <div>
                <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[10px]">Options</p>
                <div className="flex flex-col gap-[10px]">
                  <Tog label="Show icon"            val={pgIcon}      set={setPgIcon}      />
                  <Tog label="Disabled (Settings)"  val={pgDisabled}  set={setPgDisabled}  />
                </div>
              </div>
            </div>
          </CardContainer>
        </div>
      )}

      {/* ── Reference ──────────────────────────────────────────────── */}
      {tab === "reference" && (
        <div className="flex flex-col gap-[40px]">

          {/* When to use — agent guidance */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">When to use</p>
            <div className="flex flex-col gap-[10px]">
              {[
                { q: "Views inside a slide-out or panel",  a: "Place Tabs directly on the surface — no CardContainer wrapper. The component sits at the top of the view; content renders below it in the same layout area." },
                { q: "Page-level or section switcher",    a: "Use Tabs standalone (no wrapper). Place it at the top of the content area — e.g. a detail page, modal body, or sidebar panel." },
                { q: "Sequential steps (Step 1 → 2 → 3)", a: "Don't use Tabs. Use a Stepper component — tabs don't communicate order or progress." },
                { q: "Navigation between distinct pages", a: "Don't use Tabs. Use Sidebar or Topbar — tabs are for in-context switching, not route changes." },
                { q: "Dense layout, secondary nav",       a: "Use Tabs with size='s' (12px, px-12 py-8) — keeps the bar compact without losing clarity." },
                { q: "More than 5 items",                 a: "Avoid Tabs — the bar overflows most containers. Consider a Select dropdown or a scrollable nav instead." },
              ].map((r, i, a) => (
                <div key={i} className="flex gap-[16px] px-[14px] py-[12px] rounded-[6px]"
                  style={{ background: "var(--surface-raised)", borderBottom: i < a.length - 1 ? "0.5px solid var(--table-border)" : undefined }}>
                  <span className="text-[12px] font-medium flex-shrink-0 w-[220px]" style={{ color: "var(--foreground)" }}>{r.q}</span>
                  <span className="text-[12px]" style={{ color: "var(--field-supporting)" }}>{r.a}</span>
                </div>
              ))}
            </div>
          </section>

          {/* Props — TabsProps */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Props — Tabs</p>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--table-border)" }}>
              <table className="w-full text-[13px]">
                <thead>
                  <tr style={{ background: "var(--surface-raised)", borderBottom: "0.5px solid var(--table-border)" }}>
                    {["Prop", "Type", "Default", "Description"].map(h => (
                      <th key={h} className="text-left px-[14px] py-[10px] text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--field-supporting)" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    { prop: "items",     type: "TabItem[]",      def: "required",   desc: "Array of tab definitions. Each item maps to one tab button." },
                    { prop: "activeId",  type: "string",         def: "required",   desc: "id of the currently selected tab. Controls indicator and label color." },
                    { prop: "onChange",  type: "(id) => void",   def: "required",   desc: "Called when a non-disabled tab is clicked. Receives the tab id." },
                    { prop: "size",      type: '"m" | "s"',      def: '"m"',        desc: "M: 14px · px-16 py-10. S: 12px · px-12 py-8. Use S for compact layouts." },
                    { prop: "className", type: "string",         def: "undefined",  desc: "Extra Tailwind classes on the tablist container." },
                  ].map((r, i, a) => (
                    <tr key={r.prop} style={{ borderBottom: i < a.length - 1 ? "0.5px solid var(--table-border)" : "none" }}>
                      <td className="px-[14px] py-[10px] font-mono text-[12px]" style={{ color: "var(--primary)" }}>{r.prop}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]" style={{ color: "var(--field-supporting)" }}>{r.type}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]" style={{ color: "var(--field-supporting)" }}>{r.def}</td>
                      <td className="px-[14px] py-[10px] text-[12px]"           style={{ color: "var(--foreground)" }}>{r.desc}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>

          {/* TabItem type */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">TabItem type</p>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--table-border)" }}>
              <table className="w-full text-[13px]">
                <thead>
                  <tr style={{ background: "var(--surface-raised)", borderBottom: "0.5px solid var(--table-border)" }}>
                    {["Field", "Type", "Default", "Description"].map(h => (
                      <th key={h} className="text-left px-[14px] py-[10px] text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--field-supporting)" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    { field: "id",       type: "string",     def: "required",  desc: "Unique identifier — matched against activeId and returned by onChange." },
                    { field: "label",    type: "string",     def: "required",  desc: "Tab label text. Keep concise — 1 to 3 words." },
                    { field: "icon",     type: "LucideIcon", def: "undefined", desc: "Optional leading icon. 16px (M) · 14px (S). Use to reinforce tab meaning." },
                    { field: "disabled", type: "boolean",    def: "false",     desc: "Renders at 40% opacity, blocks interaction. Never disable all tabs at once." },
                  ].map((r, i, a) => (
                    <tr key={r.field} style={{ borderBottom: i < a.length - 1 ? "0.5px solid var(--table-border)" : "none" }}>
                      <td className="px-[14px] py-[10px] font-mono text-[12px]" style={{ color: "var(--primary)" }}>{r.field}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]" style={{ color: "var(--field-supporting)" }}>{r.type}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]" style={{ color: "var(--field-supporting)" }}>{r.def}</td>
                      <td className="px-[14px] py-[10px] text-[12px]"           style={{ color: "var(--foreground)" }}>{r.desc}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>

          {/* Tokens */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Design tokens</p>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--table-border)" }}>
              <table className="w-full text-[13px]">
                <thead>
                  <tr style={{ background: "var(--surface-raised)", borderBottom: "0.5px solid var(--table-border)" }}>
                    {["Token", "Role", "Dark value", "Light value"].map(h => (
                      <th key={h} className="text-left px-[14px] py-[10px] text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--field-supporting)" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    { token: "--primary",            role: "Active text + indicator border",  dark: "#2b7fff",              light: "#2173ff"              },
                    { token: "--field-supporting",   role: "Inactive text + icon",            dark: "rgba(255,255,255,0.6)", light: "#5c5c5c"              },
                    { token: "--foreground",         role: "Hover text color",                dark: "rgba(255,255,255,0.8)", light: "#1a1a1a"              },
                    { token: "--field-border",       role: "Container track border",          dark: "rgba(255,255,255,0.1)", light: "#5c5c5c"              },
                    { token: "--tabs-hover-bg",      role: "Tab hover background (Surface/Neutral/Subtle)", dark: "rgba(255,255,255,0.06)", light: "#fafafa" },

                  ].map((r, i, a) => (
                    <tr key={r.token} style={{ borderBottom: i < a.length - 1 ? "0.5px solid var(--table-border)" : "none" }}>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]" style={{ color: "var(--primary)" }}>{r.token}</td>
                      <td className="px-[14px] py-[10px] text-[12px]"           style={{ color: "var(--foreground)" }}>{r.role}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]" style={{ color: "var(--field-supporting)" }}>{r.dark}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]" style={{ color: "var(--field-supporting)" }}>{r.light}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>

          {/* Sizes */}
          <section>
            <p className="text-[11px] font-semibold uppercase tracking-widest text-[var(--field-supporting)] mb-[16px]">Sizes</p>
            <div className="rounded-[8px] overflow-hidden" style={{ border: "0.5px solid var(--table-border)" }}>
              <table className="w-full text-[13px]">
                <thead>
                  <tr style={{ background: "var(--surface-raised)", borderBottom: "0.5px solid var(--table-border)" }}>
                    {["Element", "Padding", "Gap", "Font", "Notes"].map(h => (
                      <th key={h} className="text-left px-[14px] py-[10px] text-[11px] font-semibold uppercase tracking-widest" style={{ color: "var(--field-supporting)" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {[
                    { el: "Tab M",      pad: "10 × 16 px",  gap: "6 px",  font: "14px / 500",  note: "Default · icon 16px" },
                    { el: "Tab S",      pad: "8 × 12 px",   gap: "4 px",  font: "12px / 500",  note: "Compact · icon 14px" },
                    { el: "Indicator",  pad: "—",           gap: "—",     font: "—",           note: "2px bottom border · active tab · mb-[-1px]" },
                  ].map((r, i, a) => (
                    <tr key={r.el} style={{ borderBottom: i < a.length - 1 ? "0.5px solid var(--table-border)" : "none" }}>
                      <td className="px-[14px] py-[10px] font-medium text-[12px]" style={{ color: "var(--foreground)" }}>{r.el}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]"   style={{ color: "var(--field-supporting)" }}>{r.pad}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]"   style={{ color: "var(--field-supporting)" }}>{r.gap}</td>
                      <td className="px-[14px] py-[10px] font-mono text-[11px]"   style={{ color: "var(--field-supporting)" }}>{r.font}</td>
                      <td className="px-[14px] py-[10px] text-[12px]"            style={{ color: "var(--field-supporting)" }}>{r.note}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>
        </div>
      )}
    </div>
  )
}

// ── Toggle page ─────────────────────────────────────────────────────────────

function TogglePage({ openSpec }: { openSpec: (s: SpecModal) => void }) {
  const [tab,        setTab]       = useState<"overview" | "playground" | "reference">("overview")
  const [tgSize,     setTgSize]    = useState<"default" | "sm" | "lg">("default")
  const [tgChecked,  setTgChecked] = useState(false)
  const [tgDisabled, setTgDisabled]= useState(false)
  const [showLabel,  setShowLabel] = useState(false)
  const [showDesc,   setShowDesc]  = useState(false)

  // Reference settings group
  const [settings, setSettings] = useState({
    darkMode: true,
    notifications: false,
    autoSave: true,
    analytics: false,
    betaFeatures: false,
  })
  const toggleSetting = (k: keyof typeof settings) =>
    setSettings(s => ({ ...s, [k]: !s[k] }))

  return (
    <div className="flex flex-col gap-0">
      <div className="flex items-start justify-between gap-[16px] mb-[28px]">
        <div>
          <h1 className="text-[24px] font-semibold text-[var(--foreground)]">Toggle</h1>
          <p className="text-[14px] text-[var(--field-supporting)] mt-[4px]">
            On/Off switch for binary settings that take effect immediately — no "Save" button needed.
            The thumb slides with a CSS transition. 3 sizes, 4 states (Off/On × Enabled/Disabled).
          </p>
        </div>
        <SpecButton onClick={() => openSpec("toggle")} />
      </div>

      <TabBar
        tabs={[
          { id: "overview",   label: "Overview"   },
          { id: "playground", label: "Playground" },
          { id: "reference",  label: "Reference"  },
        ]}
        active={tab}
        onChange={id => setTab(id as typeof tab)}
      />

      <div className="flex flex-col gap-[40px] pt-[32px]">

        {/* ── Overview ─────────────────────────────────────────────── */}
        {tab === "overview" && (
          <div className="flex flex-col gap-[24px]">
            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">All sizes and states</h2>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[24px] flex flex-col gap-[20px]">
                {(["lg","default","sm"] as const).map(s => {
                  const dims  = s==="lg"?"52×32px":s==="sm"?"26×16px":"39×24px"
                  return (
                    <div key={s} className="flex flex-col gap-[8px]">
                      <p className="text-[11px] font-semibold uppercase tracking-wider text-[var(--field-supporting)]">
                        Size {s.toUpperCase()} — {dims}
                      </p>
                      <div className="flex flex-wrap gap-[20px] items-center">
                        {[
                          { checked: false, disabled: false, lbl: "Off" },
                          { checked: true,  disabled: false, lbl: "On"  },
                          { checked: false, disabled: true,  lbl: "Off · Disabled" },
                          { checked: true,  disabled: true,  lbl: "On · Disabled"  },
                        ].map(c => (
                          <div key={c.lbl} className="flex flex-col gap-[6px] items-center">
                            <Toggle size={s} checked={c.checked} disabled={c.disabled} />
                            <p className="text-[11px] text-[var(--field-supporting)]">{c.lbl}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  )
                })}
              </div>
            </div>

            <div className="flex flex-col gap-[12px]">
              <h2 className="text-[16px] font-semibold text-[var(--foreground)]">With label</h2>
              <div className="rounded-[8px] border border-[var(--field-border)] p-[20px] flex flex-col gap-[16px]">
                <Toggle label="Dark mode" checked />
                <Toggle label="Email notifications" description="Receive alerts for mentions and assigned tasks" />
                <Toggle label="Beta features" description="Access experimental features before public release" disabled />
              </div>
            </div>
          </div>
        )}

        {/* ── Playground ───────────────────────────────────────────── */}
        {tab === "playground" && (
          <div className="flex flex-col gap-[20px]">
            <div className="rounded-md border border-[var(--field-border)] p-[20px] flex flex-col gap-[16px]">
              <CtrlGroup
                label="Size"
                options={[{label:"S — 26×16",value:"sm"},{label:"M — 39×24",value:"default"},{label:"L — 52×32",value:"lg"}]}
                value={tgSize}
                onChange={v => setTgSize(v as "default" | "sm" | "lg")}
              />
              <CtrlToggle label="On"       value={tgChecked}  onChange={setTgChecked} />
              <CtrlToggle label="Disabled" value={tgDisabled} onChange={setTgDisabled} />
              <CtrlToggle label="Label"    value={showLabel}  onChange={setShowLabel} />
              <CtrlToggle label="Desc"     value={showDesc}   onChange={v => { setShowDesc(v); if (v) setShowLabel(true) }} />
            </div>
            <div className="flex items-center justify-center min-h-[100px] rounded-md border border-[var(--field-border)] border-dashed px-[40px]">
              <Toggle
                size={tgSize}
                checked={tgChecked}
                disabled={tgDisabled}
                onChange={setTgChecked}
                label={showLabel ? "Enable this setting" : undefined}
                description={showDesc ? "Changes take effect immediately without saving" : undefined}
              />
            </div>
          </div>
        )}

        {/* ── Reference ────────────────────────────────────────────── */}
        {tab === "reference" && (
          <div className="flex flex-col gap-[24px]">
            <Row label="1 · Sizes — S / M / L">
              <div className="flex items-end gap-[24px]">
                {(["sm","default","lg"] as const).map(s => (
                  <div key={s} className="flex flex-col gap-[8px] items-center">
                    <Toggle size={s} checked />
                    <p className="text-[11px] text-[var(--field-supporting)]">
                      {s==="sm"?"S 26×16":s==="default"?"M 39×24":"L 52×32"}
                    </p>
                  </div>
                ))}
              </div>
            </Row>

            <Row label="2 · All 4 states — Off/On × Enabled/Disabled">
              <div className="flex flex-wrap gap-[24px] items-center">
                {[
                  { checked: false, disabled: false, lbl: "Off" },
                  { checked: true,  disabled: false, lbl: "On"  },
                  { checked: false, disabled: true,  lbl: "Off disabled" },
                  { checked: true,  disabled: true,  lbl: "On disabled"  },
                ].map(c => (
                  <div key={c.lbl} className="flex flex-col gap-[6px] items-center">
                    <Toggle checked={c.checked} disabled={c.disabled} />
                    <p className="text-[11px] text-[var(--field-supporting)]">{c.lbl}</p>
                  </div>
                ))}
              </div>
            </Row>

            <Row label="3 · Settings panel (interactive)">
              <div className="w-[320px] flex flex-col gap-0 divide-y divide-[var(--field-border)] rounded-[8px] border border-[var(--field-border)] overflow-hidden">
                {[
                  { key: "darkMode",      label: "Dark mode",           desc: "Use dark theme across the app" },
                  { key: "notifications", label: "Push notifications",  desc: "Get notified about activity" },
                  { key: "autoSave",      label: "Auto-save drafts",    desc: "Save every 30 seconds automatically" },
                  { key: "analytics",     label: "Usage analytics",     desc: "Share anonymized data to improve the product" },
                  { key: "betaFeatures",  label: "Beta features",       desc: "Early access to experimental features", disabled: true },
                ].map(row => (
                  <div key={row.key} className="flex items-center justify-between px-[16px] py-[12px]">
                    <div>
                      <p className="text-[14px] font-medium text-[var(--foreground)]">{row.label}</p>
                      <p className="text-[12px] text-[var(--field-supporting)]">{row.desc}</p>
                    </div>
                    <Toggle
                      checked={settings[row.key as keyof typeof settings]}
                      disabled={row.disabled}
                      onChange={() => !row.disabled && toggleSetting(row.key as keyof typeof settings)}
                    />
                  </div>
                ))}
              </div>
            </Row>

            <Row label="4 · Size S — compact rows">
              <div className="w-[260px] flex flex-col gap-[8px]">
                {["Verbose logging","Include timestamps","Pretty-print JSON","Stream responses"].map((opt,i) => (
                  <div key={opt} className="flex items-center justify-between">
                    <span className="text-[13px] text-[var(--field-text)]">{opt}</span>
                    <Toggle size="sm" checked={i===0||i===3} />
                  </div>
                ))}
              </div>
            </Row>
          </div>
        )}
      </div>
    </div>
  )
}

