function StatusTag({ value }: { value: string }) {
  const variantMap: Record<string, TagVariant> = {
    Active:   "success",
    Inactive: "secondary",
    Pending:  "alert",
    Paid:     "success",
    Draft:    "secondary",
  }
  return <Tag variant={variantMap[value] ?? "secondary"} size="sm">{value}</Tag>
}

